INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('03-roadmap-to-be-sky-test',1,3,'ROADMAP TO BE SKY','R.O.A.D.M.A.P - He dieu hanh quan tri noi bo',3,'draft','2026-06-20T00:00:00Z','2026-06-20T00:00:00Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fc745014-8cd6-48a8-96a2-cbb1b2bd4587','03-roadmap-to-be-sky-test',NULL,2,'3.1 Hiểu về R.O.A.D.M.A.P','31-hieu-ve-roadmap',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eeccd4aa-4f30-410b-a7cb-6cb0d4d41c63','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',0,'text','**"Lựa chọn quan trọng hơn nỗ lực” **',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f5f367e-479f-4640-9e8a-d186ce97b454','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',1,'text','Nếu đi đúng hướng, rồi sẽ đến đích; nhưng nếu đi sai hướng ngay từ đầu, thì dù có đi nhanh đến đâu cũng chỉ là vô nghĩa. **TO BE SKY** cho chúng ta **lý do để bắt đầu** và **đích đến để hướng về**; còn **R.O.A.D.M.A.P** chính là **con đường** giúp chúng ta biến lý tưởng ấy thành hiện thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90fe5078-221d-4659-9165-cecd755e465a','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',2,'text','Tôi đã dành nhiều ngày để nghiên cứu, viết ra, rồi lại bỏ xuống, viết lại, chỉnh sửa, và hoàn thiện. Đến khi R.O.A.D.M.A.P hoàn chỉnh, niềm vui của tôi không chỉ nằm ở việc kết thúc một bản thảo, mà nằm ở cảm giác rằng tất cả những gì tôi muốn truyền tải cuối cùng đã tìm được hình hài trọn vẹn. Mỗi từ, mỗi tầng, mỗi cấu trúc trong R.O.A.D.M.A.P đều không phải là những mảnh rời rạc, mà là những chặng đường nối tiếp nhau trong một hành trình lớn hơn, hành trình xây dựng một tổ chức có bản sắc, có đạo đức, có năng lực và có tương lai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06f7883f-de9e-40b1-b9ad-8e8a3bd39ebe','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',3,'text','**TO BE SKY là tinh thần**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8eee428-e3a1-4e43-865c-78bfc0e22c5c','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',4,'text','**R.O.A.D.M.A.P là lộ trình**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88e380df-0a31-49dd-b419-16c3246cdcd3','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',5,'text','Nếu SKY là lời nhắc về điều đúng đắn, thì ROADMAP là cách để điều đúng đắn ấy đi vào đời sống, thành hành động, thành hệ thống, và thành kết quả bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5baa6b5f-16da-4a13-a2b4-9b801166e375','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',6,'image',NULL,'book/03-roadmap-to-be-sky-test/01c845ce-6512-437b-b610-8e69aa1139ec-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('72f553a2-a2aa-4d12-9947-c620338eb870','03-roadmap-to-be-sky-test','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',3,'R.O.A.D.M.A.P - Hệ điều hành của một tổ chức tiến hóa','roadmap-he-ieu-hanh-cua-mot-to-chuc-tien-hoa',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9854d1ed-d297-4e87-87d5-2e4518b31fde','72f553a2-a2aa-4d12-9947-c620338eb870',7,'text','Khi nhìn lại hành trình xây dựng và điều hành tổ chức, tôi nhận ra hầu hết các mô hình quản trị đều vướng phải một điểm nghẽn chí mạng: *Lý thuyết thì rất hay, nhưng khi mang về áp dụng lại không biết phải bắt đầu từ đâu*. Chúng ta có những tầm nhìn vĩ đại, nhưng lại thiếu một hành trình từng bước để đạt được tầm nhìn ấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89a507af-3a05-4b7c-8d7d-cd3f81387b95','72f553a2-a2aa-4d12-9947-c620338eb870',8,'text','Đó là lý do tôi kiến tạo nên **R.O.A.D.M.A.P. **Đây không phải là một quy trình quản lý khô khan, mà là một **Hệ điều hành quản trị nội bộ** mang tính "Fractal" (mô hình lồng trong mô hình). Nó được sinh ra để đồng bộ trọn vẹn giữa con người và tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29922eb5-dd0d-45ac-842a-007bf81c8f96','72f553a2-a2aa-4d12-9947-c620338eb870',9,'text','R.O.A.D.M.A.P không phải là một đường thẳng có điểm kết thúc, mà là một vòng lặp tiến hóa khép kín gồm 7 tầng. Mỗi tầng vĩ mô lại cất giấu một bộ mã thực thi vi mô, dẫn dắt tổ chức đi từ bên trong nội tâm ra đến sự thịnh vượng bên ngoài:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('630b87f1-7799-452c-a597-25b7b7e50b28','72f553a2-a2aa-4d12-9947-c620338eb870',10,'text','- ***R – ROOTS (Bám rễ & Bản sắc):**** *Chúng ta bắt đầu bằng việc cắm những chiếc rễ sâu nhất vào giá trị lõi. Đây là nơi tổ chức định hình bản sắc, chuẩn hóa nguyên tắc vận hành (Operating Code) và rèn luyện sức bền để không bị bẻ gãy trước sóng gió.- ***O – ONE LIGHT (Định hướng & Chuẩn mực):*** Khi đã có gốc, chúng ta cần một ngọn đèn soi đường. Tầng này nhắc nhở rằng chúng ta là một tập thể hợp nhất (**Oneness**), làm việc dựa trên phẩm giá (**Nobility**) và được dẫn dắt bởi những giá trị đạo đức (**Ethics**) không thể thỏa hiệp.- ***A – AWAKEN (Nhận thức & Chẩn đoán):*** Đây là "mắt thần" của hệ thống. Trước khi vội vã hành động, tổ chức phải biết tự soi xét (Audit), quan sát thị trường, đào sâu nguyên nhân gốc rễ và nhạy bén nhận ra những điểm nghẽn dù là nhỏ nhất.- ***D – DEEPEN (Đào sâu & Chuẩn hóa):**** *Khi đã thấy rõ vấn đề, chúng ta không dừng lại ở lời nói. Đây là lúc bóc tách chi tiết, nâng cấp năng lực, đóng gói thành quy trình (SOP) và đưa vào kỷ luật thực thi để biến chuẩn mực thành nếp sống tự nhiên của tổ chức.- ***M – MATURE (Trưởng thành & Tối ưu):**** *Hệ thống lớn lên là chưa đủ, nó cần phải "chín". Tầng này tạo ra gia tốc (Momentum), chỉnh nhịp để toàn đội ngũ cùng tần số, hợp lực (Unite) và tinh chỉnh bộ máy để giảm thiểu mọi ma sát.- ***A – ALIGN (Đồng bộ & Tích hợp):**** *Để không trượt khỏi đường ray khi tăng trưởng nhanh, đây là lúc siết chặt đội hình. Chúng ta neo chặt mục tiêu, kết nối mọi nguồn lực và thu hẹp bớt những độ lệch pha giữa kế hoạch và thực tế.- ***P – PROSPER (Thịnh vượng & Kế thừa):*** Tầng cuối cùng kích hoạt hiệu ứng bánh đà. Giá trị được sinh sôi (Proliferate), nguồn lực được tái đầu tư và hệ sinh thái được làm giàu. Quan trọng nhất, tổ chức liên tục tự làm mới (Renew) để không bao giờ già cỗi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34ce5475-438e-4e4c-92e6-0e8d0e948015','72f553a2-a2aa-4d12-9947-c620338eb870',11,'text','Chữ **Renew** ở cuối hành trình chính là chìa khóa. Nó nối thẳng về lại chữ **ROOTS** ban đầu, tạo thành một vòng xoắn ốc đi lên vô tận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d988dd9-7882-4112-9b2b-a09794b6f7e9','72f553a2-a2aa-4d12-9947-c620338eb870',12,'text','Với R.O.A.D.M.A.P, tôi tin rằng chúng ta không chỉ đang quản trị một công việc kinh doanh. Chúng ta đang kiến tạo một sinh thể sống minh bạch trong vận hành, rõ ràng trong phối hợp, có chiều sâu về văn hóa và sở hữu năng lực tiến hóa bền vững vượt thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb','03-roadmap-to-be-sky-test','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',3,'Triết lý lõi của mô hình: Tổ chức là một thực thể sống','triet-ly-loi-cua-mo-hinh-to-chuc-la-mot-thuc-the-song',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('52182746-5dcb-4843-9c35-d52d48e9c75d','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',13,'text','R.O.A.D.M.A.P được khơi nguồn từ một niềm tin kiên định: Một tổ chức vĩ đại không bao giờ định nghĩa sự bền vững chỉ bằng những con số trên báo cáo doanh thu. Sức mạnh thực sự của nó phải được bám rễ sâu vào bản sắc, ranh giới đạo đức, chiều sâu năng lực con người và khả năng tự học hỏi từ chính mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('275e28cd-e3eb-456a-af85-de448889e69a','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',14,'text','Trong môi trường đặc thù như y tế, phòng khám nha khoa tuyệt đối không phải là một "cỗ máy sản xuất dịch vụ" vô tri. Nó là một **thực thể sống**. Ở đó, một chuỗi phản ứng dây chuyền luôn âm thầm diễn ra: Văn hóa định hình hành vi của bác sĩ và nhân viên; hành vi ấy trực tiếp chạm đến trải nghiệm của bệnh nhân; trải nghiệm kiến tạo nên uy tín; và cuối cùng, uy tín quay trở lại làm mạch máu nuôi sống toàn bộ hệ sinh thái.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6a5aff5-52d4-4a53-b7bd-d08c4cb97f11','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',15,'text','Đó là lý do R.O.A.D.M.A.P từ chối bắt đầu bằng những câu hỏi mang tính cơ giới như: *"Làm sao để tăng số ca điều trị?"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c319fa3-1281-4733-84a3-6abb5b1d18e6','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',16,'text','Thay vào đó, hệ thống buộc chúng ta phải đi tìm sự thật từ cội nguồn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4a06e2c-52df-420d-a3e7-543437391ba2','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',17,'text','- *Chúng ta là ai và phụng sự dựa trên giá trị nào?*- *Những mảnh ghép nào thực sự phù hợp với văn hóa của tổ chức này?*- *Hệ thống đang âm thầm tắc nghẽn ở đâu?*- *Ai đang làm đúng vai trò của mình, và kết quả nào mới thực sự xứng đáng được tôn vinh?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f87b98c1-0d62-43f7-8137-a1c9fc6087a7','9a9adecf-ba72-43a9-a6fe-4db1f51bcbfb',18,'text','Sự khác biệt lớn nhất của R.O.A.D.M.A.P nằm ở đây: Nó vượt xa những chuỗi quy trình (workflow) hay bảng biểu KPI khô khan để trở thành một **kiến trúc quản trị có chiều sâu văn hóa và tính nhân bản sâu sắc**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4aca8be8-94da-4810-b8a0-bc4c04da0f17','03-roadmap-to-be-sky-test','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',3,'Mantra điều hành kiến trúc R.O.A.D.M.A.P','mantra-ieu-hanh-kien-truc-roadmap',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae70f656-6883-428c-a1be-cae6c965bfaa','4aca8be8-94da-4810-b8a0-bc4c04da0f17',19,'text','Đây là kim chỉ nam, là hệ tư tưởng xuyên suốt mà bất kỳ ai vận hành hệ thống này cũng phải nằm lòng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e98008bd-9448-4820-8c61-66142dd8139a','4aca8be8-94da-4810-b8a0-bc4c04da0f17',20,'text','"Một phòng khám nha khoa tầm thường cố quản lý con người bằng sự giám sát khắt khe và nỗi sợ hãi chặng ngắn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87286717-8ffc-4260-9034-98a247233000','4aca8be8-94da-4810-b8a0-bc4c04da0f17',21,'text','Nhưng một đế chế nha khoa vĩ đại sẽ điều hành tổ chức bằng một hệ mã nguồn liên thông nối liền từ gốc rễ tâm hồn cho đến từng hành động nhỏ nhất trên thực địa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0adb29d4-bea7-45f2-87b2-ab8cd49a6504','4aca8be8-94da-4810-b8a0-bc4c04da0f17',22,'text','Hãy để R.O.A.D.M.A.P trở thành thước đo của sự chuẩn mực, chiếc la bàn giữ gìn đạo đức, và là cỗ động cơ mạnh mẽ nhất thúc đẩy phòng khám của bạn không ngừng tự tiến hóa, vươn lên những đỉnh cao thịnh vượng mới."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('69409dfa-2709-4fec-8fd6-3eaacbea593e','03-roadmap-to-be-sky-test','fc745014-8cd6-48a8-96a2-cbb1b2bd4587',3,'Ba lăng kính tự phản biện về hệ điều hành R.O.A.D.M.A.P','ba-lang-kinh-tu-phan-bien-ve-he-ieu-hanh-roadmap',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bac53918-a150-42b2-9536-abd815292537','69409dfa-2709-4fec-8fd6-3eaacbea593e',23,'text','Việc kiến tạo R.O.A.D.M.A.P không nên được hiểu như hành động xây thêm một bộ công cụ quản trị để áp đặt lên tổ chức. Ở cấp độ sâu hơn, đây là nỗ lực kiến tạo một cấu trúc tự soi chiếu, nơi bản thân hệ điều hành cũng phải chịu sự kiểm định nghiêm ngặt trước các câu hỏi nền tảng nhất về con người, tổ chức và quy luật vận động của sự phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51594a17-ba62-4380-8389-7a453673cb28','69409dfa-2709-4fec-8fd6-3eaacbea593e',24,'text','Một mô hình chỉ có thể đi đường dài khi nó không chỉ hiệu quả trong thực thi, mà còn đủ chiều sâu để tự phản biện. Chính vì vậy, R.O.A.D.M.A.P cần được đặt dưới ba lăng kính triết học cốt lõi nhằm kiểm định bản chất tư tưởng của nó: vũ trụ quan, nhân sinh quan và thế giới quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3dd17ee-0ddd-4234-8360-af903041e6c6','69409dfa-2709-4fec-8fd6-3eaacbea593e',25,'text','Ba lăng kính này lần lượt trả lời ba câu hỏi nền tảng. Thứ nhất, tổ chức được giả định là đang vận hành theo quy luật nào của đời sống? Thứ hai, con người trong hệ thống được nhìn nhận như thế nào: như một công cụ sản xuất hay như một chủ thể có phẩm giá và khả năng trưởng thành? Thứ ba, văn hóa, chiến lược và vận hành thực địa có được tích hợp thành một chỉnh thể nhất quán hay không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4289b136-14b2-4ae3-a8b8-32d909923277','69409dfa-2709-4fec-8fd6-3eaacbea593e',26,'text','Dưới lăng kính vũ trụ quan, R.O.A.D.M.A.P phản ánh rõ một tư duy biện chứng và hữu cơ. Mô hình này không xem tổ chức là tập hợp tĩnh của các phòng ban, cũng không hiểu doanh nghiệp như một cỗ máy vận hành thuần cơ giới. Trái lại, nó mặc định rằng tổ chức là một sinh thể sống, liên tục vận động, liên tục phát sinh mâu thuẫn nội tại và liên tục tự điều chỉnh để tiến hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('376a70b6-0174-4b81-b742-130bbd1b4463','69409dfa-2709-4fec-8fd6-3eaacbea593e',27,'text','Chuỗi phát triển từ **ROOTS → ONE LIGHT → AWAKEN → DEEPEN → MATURE → ALIGN → PROSPER** cho thấy một giả định trung tâm: phát triển không diễn ra theo đường thẳng, mà vận động thông qua nhận diện lệch pha, chuyển hóa điểm nghẽn, gia cố năng lực nền và tái đồng bộ toàn hệ thống. Nói cách khác, tăng trưởng bền vững không đến từ việc né tránh xung đột, mà đến từ khả năng đọc đúng mâu thuẫn và xử lý đúng mâu thuẫn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4becc4d-bb03-4237-a5be-dc8ada1e0bd4','69409dfa-2709-4fec-8fd6-3eaacbea593e',28,'text','Tinh thần này thể hiện đậm nhất ở tầng **AWAKEN** và **DEEPEN**. Trong logic của mô hình, các khoảng cách giữa thực trạng và mục tiêu, các điểm nghẽn vận hành, các sai lệch chuẩn hoặc tín hiệu cảnh báo sớm không phải là “lỗi” để che giấu, mà là nguồn dữ liệu sống để kích hoạt quá trình nâng cấp hệ thống. Chính điều này khiến R.O.A.D.M.A.P đặc biệt phù hợp với môi trường nha khoa, nơi chuyên môn lâm sàng, trải nghiệm bệnh nhân, dữ liệu vận hành, tài chính và niềm tin thương hiệu luôn tác động chéo lên nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23bba62e-3147-4e06-9de1-d36a2206a39a','69409dfa-2709-4fec-8fd6-3eaacbea593e',29,'text','Tuy nhiên, cùng với sức mạnh ấy là một nguy cơ nội tại. Khi mô hình đi xuống các tầng như **DEEPEN** hoặc **PROSPER**, đặc biệt tại các cơ chế như **Enforce** và **Optimize**, hệ điều hành rất dễ trượt sang quỹ đạo cơ giới hóa. Nếu người lãnh đạo đồng nhất quản trị với siết checklist, chuẩn hóa triệt để và đo lường quá dày đặc, tổ chức sẽ dần đánh mất bản chất sống động của mình. Trong bối cảnh y tế, rủi ro này đặc biệt nghiêm trọng vì nó có thể làm suy giảm không gian dành cho trực giác lâm sàng, phán đoán nghề nghiệp và y đức của bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('130eeab2-b4a9-492c-a40a-9ee73c5ac2c7','69409dfa-2709-4fec-8fd6-3eaacbea593e',30,'text','Vì vậy, xét ở bình diện vũ trụ quan, R.O.A.D.M.A.P là một mô hình đúng hướng về mặt tiến hóa, nhưng chỉ giữ được sức sống khi được vận hành như một cơ thể hữu cơ, không phải như một thiết bị kỹ trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c00c514-cc57-47cf-b9a0-942997f7b788','69409dfa-2709-4fec-8fd6-3eaacbea593e',31,'text','Nếu vũ trụ quan đặt câu hỏi về quy luật vận hành của tổ chức, thì nhân sinh quan buộc mô hình phải trả lời một câu hỏi sâu hơn: con người trong hệ điều hành này được định vị là ai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3b17147-437a-4887-aa2f-ed2e935ae9d9','69409dfa-2709-4fec-8fd6-3eaacbea593e',32,'text','Ở điểm này, R.O.A.D.M.A.P thể hiện một lập trường rõ ràng: từ chối cách nhìn nhân sự như những đơn vị lao động bị quy giản thành KPI. Mô hình xuất phát từ giả định rằng con người là trung tâm tạo giá trị, là chủ thể có bản sắc, có nhân cách, có khả năng tự hoàn thiện và cần được đặt trong đúng môi trường để phần tốt đẹp nhất được khai mở.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81fc14ba-f781-420a-a2e5-1a85c984dc67','69409dfa-2709-4fec-8fd6-3eaacbea593e',33,'text','Chính vì thế, hai tầng đầu tiên của hệ điều hành là **ROOTS** và **ONE LIGHT** không khởi sự bằng câu hỏi “làm được gì”, mà bằng những câu hỏi sâu hơn: nền giá trị nào đang định hình con người này, họ có cùng DNA cốt lõi với tổ chức hay không, họ có được dẫn dắt dưới ánh sáng của sự chính trực hay không, và họ có đang được đặt đúng vai để trưởng thành hay không. Đây là cách mô hình đưa phần sâu kín nhất của con người đi trước phần biểu hiện bề mặt của hiệu suất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5bedc3c9-ee80-4d6a-bedc-d2449f3f9e1a','69409dfa-2709-4fec-8fd6-3eaacbea593e',34,'text','Đối với môi trường y tế và nha khoa, cách tiếp cận này có ý nghĩa đặc biệt. Bởi trong những hệ thống chăm sóc sức khỏe, giá trị của đội ngũ không thể chỉ được đo bằng sản lượng hay doanh thu. Một hệ điều hành đúng đắn phải đồng thời bảo vệ danh dự nghề nghiệp, lòng tự trọng chuyên môn, phẩm chất đạo đức và sự tử tế trong quan hệ giữa người làm nghề với bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06747483-e259-4bc5-b523-727e97e9ec92','69409dfa-2709-4fec-8fd6-3eaacbea593e',35,'text','Tuy nhiên, cũng như mọi hệ thống quản trị trưởng thành, thách thức lớn nhất không nằm ở phần tuyên ngôn, mà nằm ở phần thực thi. Khi mô hình dịch chuyển xuống các tầng như **DEEPEN**, **ALIGN** và **PROSPER**, tổ chức bắt đầu đi vào các cơ chế đánh giá, chuẩn hóa, xếp loại và tối ưu. Chính tại đây xuất hiện một nghịch lý quan trọng: công cụ được tạo ra để hỗ trợ con người có thể quay ngược lại để quy giản con người.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cbeba669-8ca7-48f7-b032-e90af0ca77fe','69409dfa-2709-4fec-8fd6-3eaacbea593e',36,'text','Các chỉ số như Ethics Score, DNA Match hay bất kỳ hình thức lượng hóa nào khác chỉ có giá trị khi chúng đóng vai trò là tín hiệu khởi đầu cho đối thoại. Nếu chúng trở thành phán quyết cuối cùng về phẩm chất con người, hệ điều hành sẽ đánh mất chính nền tảng nhân văn mà nó tuyên bố bảo vệ. Bởi vậy, về mặt nhân sinh quan, R.O.A.D.M.A.P chỉ giữ được tính chính đáng khi sau mỗi chỉ số vẫn còn đối thoại, sau mỗi đánh giá vẫn còn mentoring, và sau mỗi cảnh báo vẫn còn chỗ cho sự thấu cảm của người dẫn dắt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5658cf71-2b93-4d8e-bbc3-c76565285667','69409dfa-2709-4fec-8fd6-3eaacbea593e',37,'text','Ở cấp độ thế giới quan, R.O.A.D.M.A.P không chỉ là một framework vận hành. Nó mang dáng dấp của một hệ tư tưởng quản trị hoàn chỉnh, trong đó tổ chức được nhìn như một chỉnh thể phải được hợp nhất từ gốc rễ đến thịnh vượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba268107-c350-42e1-9f3e-8738650e581a','69409dfa-2709-4fec-8fd6-3eaacbea593e',38,'text','Điểm cốt lõi của thế giới quan này là phủ nhận sự chia cắt giữa văn hóa, chiến lược và vận hành thực địa. Đây là một vấn đề phổ biến của nhiều doanh nghiệp: giá trị được phát biểu ở tầng truyền thông, chiến lược được thiết kế ở tầng lãnh đạo, còn thực địa lại vận hành theo một logic hoàn toàn khác. Sự đứt gãy ấy chính là nguồn gốc của mất phương hướng, mất niềm tin và mất năng lực tăng trưởng bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6afb9fe4-d94b-4e65-a7b3-fd25115abfdf','69409dfa-2709-4fec-8fd6-3eaacbea593e',39,'text','R.O.A.D.M.A.P được thiết kế để xử lý triệt để điểm đứt gãy này. Trong cấu trúc của nó, bản sắc phải nối được với đạo đức; đạo đức phải nối được với nhận thức; nhận thức phải chuyển hóa thành quy trình; quy trình phải đi vào sự trưởng thành hữu cơ của tổ chức; sự trưởng thành phải dẫn tới đồng bộ nguồn lực; và toàn bộ quá trình ấy phải mở ra thịnh vượng mà không đánh mất linh hồn ban đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc4b7d45-c4b2-42d4-bfe5-33bd45b7f49b','69409dfa-2709-4fec-8fd6-3eaacbea593e',40,'text','Chính nhờ vậy, mô hình này đặc biệt có giá trị trong bối cảnh các chuỗi nha khoa đa chi nhánh. Khi quy mô gia tăng, sự phân mảnh không chỉ xuất hiện ở quy trình, mà còn xuất hiện ở tinh thần vận hành. Một đơn vị có thể tăng trưởng doanh thu nhưng suy giảm đạo đức. Một đội ngũ có thể tuân thủ SOP nhưng mất đi sự sống nghề nghiệp. Một bộ máy có thể hiệu quả về số liệu nhưng lại nghèo nàn về ý nghĩa. R.O.A.D.M.A.P được hình thành để chống lại kiểu tăng trưởng đánh đổi này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01f6b7f0-6b80-40a3-86eb-5e859ce7b6b4','69409dfa-2709-4fec-8fd6-3eaacbea593e',41,'text','**ROOTS, ONE LIGHT, AWAKEN** tạo thành “thượng tầng tư tưởng” của hệ điều hành, nơi phần hồn của tổ chức được hình thành. Ngược lại, **DEEPEN, MATURE, ALIGN, PROSPER** tạo thành “hạ tầng thực thi”, nơi phần hồn ấy phải được chuyển hóa thành kỷ luật, cơ chế, hành động và kết quả.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('207be941-5753-499f-8e13-c0c178b7c90b','69409dfa-2709-4fec-8fd6-3eaacbea593e',42,'text','Ý nghĩa của sự phân tầng này là rất rõ: nếu không có thượng tầng tư tưởng, hạ tầng thực thi sẽ trở thành kỹ trị lạnh lùng; nhưng nếu không có hạ tầng thực thi, thượng tầng tư tưởng sẽ chỉ dừng ở mức tuyên ngôn đạo đức. Giá trị của R.O.A.D.M.A.P nằm ở chỗ nó cố gắng nối hai miền ấy vào cùng một vòng sống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2264fcc4-06d8-400c-8205-628d816cf86b','69409dfa-2709-4fec-8fd6-3eaacbea593e',43,'image',NULL,'book/03-roadmap-to-be-sky-test/2c9a4c92-bd4a-4bda-8986-5b746fec9e04-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24c58e16-f1b4-4814-85fd-30dda2dc6904','69409dfa-2709-4fec-8fd6-3eaacbea593e',44,'text','Nhìn một cách tổng thể, R.O.A.D.M.A.P sở hữu cấu trúc tư tưởng khá vững chãi: mạch lạc về vũ trụ quan, có nền tảng rõ về nhân sinh quan và tương đối trọn vẹn về thế giới quan. Sức mạnh lớn nhất của mô hình không nằm ở việc tạo thêm một bộ công cụ quản lý, mà ở chỗ nó trả lời được những câu hỏi tối hậu của một tổ chức: quản trị để làm gì, con người mang danh dự gì trong hệ thống, sự tiến hóa diễn ra theo quy luật nào, và điểm nghẽn được chuyển hóa ra sao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29340b5f-e093-4e2b-b616-41225f2e2eb0','69409dfa-2709-4fec-8fd6-3eaacbea593e',45,'text','Tuy nhiên, để chữ **Renew** ở cuối hành trình có thể thật sự quay lại nuôi dưỡng **ROOTS**, tạo thành một vòng xoắn ốc đi lên thay vì một chu kỳ lặp mòn, người đứng đầu phải giữ được ba điểm neo cân bằng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a56a3fb-0105-4ada-8f64-daf678b1ce04','69409dfa-2709-4fec-8fd6-3eaacbea593e',46,'text','- Thứ nhất, không để các tầng như **DEEPEN** và **PROSPER** trượt sang cơ giới hóa. Kỷ luật và tối ưu là cần thiết, nhưng không được làm đội ngũ trở thành những bánh răng vô hồn.- Thứ hai, phải duy trì dòng chảy đối thoại sống ở các tầng như **MATURE** và **ALIGN**. Dashboard, score hay alert chỉ là tín hiệu tham chiếu; sự chỉnh nhịp thật sự luôn phải đi qua đối thoại, khai vấn và niềm tin giữa người với người.- Thứ ba, phải bảo vệ thánh đường chuyên môn tại **AWAKEN** và trên toàn bộ trục vận hành. Dữ liệu chỉ nên đóng vai trò tham mưu; nó không được phép lấn át trực giác lâm sàng, phán đoán chuyên môn và y đức của bác sĩ trong thực hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c38ed464-007d-4618-ad42-bbddb2544ee1','69409dfa-2709-4fec-8fd6-3eaacbea593e',47,'text','Nếu giữ được ba điểm neo này, R.O.A.D.M.A.P có thể vượt qua giới hạn của một framework quản trị thông thường. Khi đó, nó không chỉ là một hệ điều hành dành cho tăng trưởng, mà trở thành một triết lý điều hành tổ chức: chặt chẽ trong cấu trúc, mạnh mẽ trong thực thi, nhưng vẫn giữ được chiều sâu nhân bản và phẩm giá nghề nghiệp của ngành nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('79eb2432-6f77-45ed-a0ad-8fc15c81c03d','03-roadmap-to-be-sky-test',NULL,2,'3.2 LAYER 1: R - ROOTS (GỐC RỄ)','32-layer-1-r-roots-goc-re',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ae9cc38-7333-4d10-8ab1-a80b95300249','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',48,'text','**Nền tảng căn bản nhất trả lời câu hỏi: "Chúng ta là ai và tại sao chúng ta tồn tại?"**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2e7a4b2-2f68-414b-99bc-84e90d7531ec','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',49,'text','Ca dao Việt Nam có câu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a321c34b-8329-4489-a4fc-71d4d3f11d9f','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',50,'text','*"Cây có gốc mới nở ngành xanh ngọn*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('faabe828-0bf6-44d9-8edc-8303f0912859','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',51,'text','*Nước có nguồn mới bể rộng sông sâu*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66fd102a-d618-4a06-861b-832cd8e7384c','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',52,'text','*Người ta nguồn gốc từ đâu*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e8758c22-348e-45f9-855d-176cad00ffbd','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',53,'text','*Có tổ tiên trước rồi sau có mình."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('197a69cc-fcf5-44a6-abb2-15adb4cd2465','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',54,'text','Bất cứ một cái cây nào dù sinh sản bằng hạt hay bằng thân thì điều kiện đầu tiên để nó bắt đầu 1 sự sống là **tạo rễ.** Một cái cây muốn vươn cao, tỏa bóng mát và chống chọi được giông bão thương trường thì bộ rễ phải cắm thật sâu vào lòng đất. Thân thì luôn đi lên, cành lá thì luôn tìm nơi có ánh sáng nhưng rễ lại khác. Rễ chấp nhận đi vào nơi tối tăm nhất, dơ bẩn nhất, chật chội nhất để tìm nguồn nước, dưỡng chất, giữ cho cái cây luôn vững chãi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccfb0065-219e-4eab-a3e1-711c322d8c84','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',55,'text','**Đối với cá nhân**, đi vào gốc rễ là đi khám phá **chân tâm** của mình. Hành trình tu sửa của mỗi người bản chất là hành trình **soi sáng** những nơi tối tăm nhất của tâm hồn, tu sửa những điều sai trái, và nuôi dưỡng lương tri bằng những điều cao đẹp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cf612dd-18ac-46b1-b584-7d20144cf660','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',56,'text','**Đối với tổ chức**, dù nhỏ hay lớn, nếu muốn trường tồn thì phải có bản sắc đủ sâu, phải luôn có một nền tảng vững chắc để làm điểm tựa cho việc **luôn làm đúng** ngay cả trong những hoàn cảnh ngặt nghèo nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6aabf86c-9f75-46a0-9f76-7cfe2953827e','03-roadmap-to-be-sky-test','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',3,'R - Radicle','r-radicle',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8c64476-06ce-4a81-87b3-b2b42b863843','6aabf86c-9f75-46a0-9f76-7cfe2953827e',57,'image',NULL,'book/03-roadmap-to-be-sky-test/e3f035b7-12b6-45ec-810c-afe3b38b0cc8-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75ded9b0-d18f-4fb0-af22-30368c55d695','6aabf86c-9f75-46a0-9f76-7cfe2953827e',58,'text','**Rễ mầm - Bộ gen quyết định cấu trúc và cũng là "Linh Hồn" của tổ chức.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('195f3ca4-4ff7-485f-8bf5-bb935bf3d372','6aabf86c-9f75-46a0-9f76-7cfe2953827e',59,'text','Trong sinh học, **radicle** là chiếc rễ mầm đầu tiên chọc thủng lớp vỏ hạt để lao xuống lòng đất. Đó là phản xạ sinh tồn nguyên thủy nhất của một mầm sống: trước khi vươn lên ánh sáng, nó phải tìm được điểm bám sâu vào đất mẹ. Từ hình ảnh đó, Radicle trong hệ điều hành R.O.A.D.M.A.P được dùng để chỉ phần gốc nguyên bản nhất của một tổ chức: lý do sâu xa khiến nó được khai sinh, sẵn sàng đánh đổi nguồn lực, thời gian và cả những tổn thất vô hình để tồn tại và lớn lên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0df3dc1e-977d-4fbb-ba42-33c9620c95ac','6aabf86c-9f75-46a0-9f76-7cfe2953827e',60,'text','Ở cấp độ quản trị, Radicle không phải là một khẩu hiệu truyền thông. Nó là câu trả lời cho câu hỏi nền tảng nhất: **vì sao phòng khám này phải tồn tại?** Nếu câu trả lời ấy mờ nhạt, toàn bộ kiến trúc bên trên sẽ sớm trở nên mong manh. Nếu lý do bắt đầu đủ mạnh, đủ thật và đủ sâu, nó sẽ trở thành chiếc rễ cọc cứng cáp, từ đó các “rễ phụ” như văn hóa, chiến lược, đội ngũ, cơ chế và tăng trưởng mới có chỗ bám để phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('080c9ceb-d314-4b4c-8b22-be4ba5e9769b','6aabf86c-9f75-46a0-9f76-7cfe2953827e',61,'text','Chính vì vậy, Radicle gắn trực tiếp với khái niệm **Sứ mệnh (Mission)**. Sứ mệnh không phải là phần trang trí treo tường, mà là logic tồn tại của doanh nghiệp. Nó xác định doanh nghiệp đang lấy nỗi đau nào của thị trường làm điểm xuất phát, đang giải quyết điều gì có ý nghĩa thật, và đang cam kết tạo ra giá trị gì đủ lớn để được thị trường nuôi sống lâu dài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7c9fade-7195-407c-bb3f-1b1ed048c2b5','6aabf86c-9f75-46a0-9f76-7cfe2953827e',62,'text','**Sứ mệnh cộng sinh**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b49c127-81cc-4f13-8a1b-e0622faab429','6aabf86c-9f75-46a0-9f76-7cfe2953827e',63,'text','Một cái cây không tồn tại tách rời khỏi trời đất. Nó sống được nhờ đất, nước, khí trời; nhưng đồng thời cũng trả lại bóng mát, độ ẩm, sự che chở và dưỡng chất cho hệ sinh thái xung quanh. Tổ chức cũng vận hành theo quy luật cộng sinh tương tự: không có doanh nghiệp nào tồn tại nếu không được nuôi sống bởi thị trường; và cũng không có thị trường nào tiếp tục nuôi một doanh nghiệp nếu doanh nghiệp ấy không còn tạo ra giá trị thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cccccd8-ac38-4930-a883-82954c8511a7','6aabf86c-9f75-46a0-9f76-7cfe2953827e',64,'text','Trong ngữ cảnh phòng khám, khách hàng chính là “đất trời” nuôi sống tổ chức. Họ là người trao dòng tiền, niềm tin và cơ hội tồn tại cho phòng khám. Nhưng điều họ trả tiền không phải là để nuôi giấc mơ của người sáng lập, càng không phải để duy trì sự hiện diện hình thức của một thương hiệu. Họ chỉ sẵn sàng chi trả khi phòng khám thực sự giúp họ giảm bớt nỗi đau, xoa dịu nỗi sợ và cải thiện chất lượng cuộc sống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('059d51fe-4899-446a-81e2-32c47ec5277c','6aabf86c-9f75-46a0-9f76-7cfe2953827e',65,'text','Từ đó có thể rút ra một nguyên tắc quản trị rất thực tế: sứ mệnh chỉ có giá trị khi nó gắn với một nỗi đau có thật của thị trường. Những câu chữ hoa mỹ, những tuyên ngôn nghe lớn lao nhưng tách rời thực tiễn thường không đủ sức dẫn dắt tổ chức trong những thời điểm khó khăn. Khi áp lực doanh thu, nhân sự và vận hành đồng loạt xuất hiện, thứ giữ cho tổ chức không lệch hướng không phải là ngôn từ đẹp, mà là một lý do tồn tại đủ thật để mọi người còn muốn tiếp tục tin và đi cùng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25d4ca4e-87b6-4b96-b909-e65f979ccd90','6aabf86c-9f75-46a0-9f76-7cfe2953827e',66,'text','Vì vậy, câu hỏi cốt lõi của Radicle không phải là “phòng khám muốn trở thành điều gì”, mà là: **nỗi đau cốt lõi nào ngoài thị trường đang nhức nhối đến mức phòng khám này buộc phải xuất hiện để giải quyết?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6642fea-2346-430a-9a34-39e3b4f22359','6aabf86c-9f75-46a0-9f76-7cfe2953827e',67,'text','**Đủ gần, đủ thật**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f830d844-4c8c-4730-9b9e-2250cd04a4b7','6aabf86c-9f75-46a0-9f76-7cfe2953827e',68,'text','Một sai lầm phổ biến của nhiều tổ chức non trẻ là xây dựng sứ mệnh theo kiểu vĩ cuồng: muốn giải cứu cả thế giới, muốn thay đổi toàn ngành ngay từ ngày đầu, muốn ôm lấy những mục tiêu vượt xa năng lực thực tế của mình. Nhưng trong quy luật tự nhiên, một cái cây chỉ có thể sống tốt trên đúng mảnh đất nơi bộ rễ của nó cắm xuống. Nó không thể đồng thời nuôi sống cả một hệ sinh thái cách nó nửa vòng trái đất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1098156d-d34f-47d7-a34c-6228218025ce','6aabf86c-9f75-46a0-9f76-7cfe2953827e',69,'text','Tương tự, một phòng khám chỉ nên bắt đầu từ mảnh đất thật mà mình đang đứng trên đó: địa bàn phục vụ, tệp bệnh nhân cụ thể, loại nỗi đau cụ thể và năng lực chữa lành thực tế mà đội ngũ đang sở hữu. Sứ mệnh không cần phô trương để gây ấn tượng với toàn thế giới. Điều cần thiết hơn là phải trở thành một điểm tựa đủ rõ, đủ khác biệt và đủ đáng tin trong lòng những người thực sự sẵn sàng trao tiền bạc và niềm tin để đổi lấy sự an tâm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4977f8d-f5df-47e1-a556-23b26ee45953','6aabf86c-9f75-46a0-9f76-7cfe2953827e',70,'text','Ở đây, “khác biệt” không đồng nghĩa với lập dị hay phô diễn thương hiệu. Khác biệt ở tầng Radicle là sự khác biệt về lý do tồn tại và về lời hứa giá trị. Tổ chức không cần cố gắng trở nên đặc biệt trong mắt tất cả mọi người; tổ chức chỉ cần trở nên không thể thay thế trong tâm trí đúng nhóm khách hàng mà mình cam kết phục vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d38332c-9fe0-4450-9bc6-bd1f9d64431f','6aabf86c-9f75-46a0-9f76-7cfe2953827e',71,'text','**Ví dụ ứng dụng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f93a7493-d546-49fb-8d0f-a45800ae98c2','6aabf86c-9f75-46a0-9f76-7cfe2953827e',72,'text','Một ví dụ điển hình cho việc xác lập Radicle là lựa chọn theo đuổi hệ giá trị **“Nha khoa Bảo tồn”**. Trong bối cảnh thị trường hiện nay, đây không chỉ là một định vị chuyên môn, mà còn là một tuyên ngôn quản trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a29e8272-925e-492c-aa05-e61ee38f0853','6aabf86c-9f75-46a0-9f76-7cfe2953827e',73,'text','*1. Vùng tối thị trường*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e44c6d41-7fbd-4edf-8d70-f212e8b9eeb5','6aabf86c-9f75-46a0-9f76-7cfe2953827e',74,'text','Thực trạng “nha khoa chộp giật” là hệ quả của việc đặt doanh số ngắn hạn lên trên đạo đức nghề nghiệp và lợi ích sinh học dài hạn của bệnh nhân. Việc lạm dụng chỉ định, đặc biệt trong các dịch vụ thẩm mỹ như mài răng thật để bọc sứ một cách thiếu kiểm soát, không chỉ gây tổn hại mô răng mà còn làm xói mòn lòng tin xã hội đối với ngành nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02fa86d7-0fda-4f8e-b2bd-c5b4bbf10987','6aabf86c-9f75-46a0-9f76-7cfe2953827e',75,'text','Dưới góc độ quản trị, đây không đơn thuần là sai lệch chuyên môn. Nó phản ánh sự thất bại trong việc thiết lập tính chính trực ở tầng gốc của doanh nghiệp. Khi một tổ chức bắt đầu nhìn khách hàng như “mã doanh thu”, tổ chức ấy đồng thời tự cắt đứt mối liên kết bền vững với thị trường và tự đẩy mình vào nguy cơ khủng hoảng danh tiếng dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4774d4f8-96a1-4fd5-9d33-2cef4c662f01','6aabf86c-9f75-46a0-9f76-7cfe2953827e',76,'text','*2. Radicle bảo tồn*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d79faab-9fea-4755-afbb-bf9311661392','6aabf86c-9f75-46a0-9f76-7cfe2953827e',77,'text','Trong bối cảnh đó, lựa chọn “Nha khoa Bảo tồn” chính là hành động xác lập Radicle. Thay vì chọn con đường doanh thu nhanh, phòng khám xác định rõ vai trò của mình là một lực cản cần thiết trước xu hướng điều trị thiên lệch vì lợi nhuận. Nói cách khác, tổ chức quyết định đứng về phía bảo vệ giá trị sinh học thật của bệnh nhân, ngay cả khi lựa chọn ấy khó hơn, chậm hơn và đòi hỏi nhiều kỷ luật đạo đức hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abde3a71-f3e7-4ae7-9d1d-97de3c69ef94','6aabf86c-9f75-46a0-9f76-7cfe2953827e',78,'text','Khi tuyên ngôn “bảo vệ tài sản răng thật của khách hàng” được xác lập, nó trở thành chiếc rễ cọc của toàn hệ thống. Mọi hoạt động chuyên môn, tư vấn, truyền thông và quản trị từ đó không còn là những hành vi rời rạc, mà được quy tụ vào cùng một lời hứa trung tâm. Từ đây, điều trị không chỉ là giao dịch, mà trở thành sự thực thi một cam kết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4fc6d96b-ee55-47eb-9eca-bb926cde0393','6aabf86c-9f75-46a0-9f76-7cfe2953827e',79,'text','Sâu hơn nữa, lựa chọn này đồng nghĩa với việc doanh nghiệp chấp nhận gắn mình với trách nhiệm trọn đời đối với niềm tin. Mỗi lần kiên nhẫn giữ răng, mỗi lần từ chối một chỉ định dễ sinh tiền nhưng không chính đáng, phòng khám đang tích lũy một loại tài sản vô hình nhưng bền vững hơn mọi chiến dịch quảng cáo: **vốn niềm tin**. Trong các ngành dịch vụ y tế, đây chính là loại tài sản quyết định khả năng sống sót qua biến động thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3a5e5c1-7b76-4c4b-841b-ca564853bae3','6aabf86c-9f75-46a0-9f76-7cfe2953827e',80,'text','*3. Giá trị chiến lược*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d368e03d-4121-48e5-89bb-32d45eb3df52','6aabf86c-9f75-46a0-9f76-7cfe2953827e',81,'text','Việc xác lập sứ mệnh dựa trên nỗi đau cốt lõi không chỉ tạo ra ý nghĩa biểu tượng. Nó còn mang lại những lợi thế quản trị cụ thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9284f11-7bc6-4396-87fe-f97052d8f101','6aabf86c-9f75-46a0-9f76-7cfe2953827e',82,'text','- **Định hướng chính sách**: Nguyên tắc bảo tồn được đặt ra trước các quyết định kinh doanh, từ đó hình thành một lằn ranh đỏ rõ ràng cho mọi chiến lược doanh thu.- **Sàng lọc nhân sự**: Một sứ mệnh đủ rõ sẽ thu hút những bác sĩ và cộng sự có cùng hệ giá trị, đồng thời tự động loại trừ những cá nhân mang tư duy trục lợi hoặc thiếu phù hợp văn hóa.- **Tăng hiệu quả tổ chức dài hạn**: Khi đội ngũ hành động trong một môi trường có chính trực và nhất quán, niềm tin nội bộ và niềm tin khách hàng sẽ cùng tăng. Đây là nền móng của lợi thế cạnh tranh bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06b3c97d-4dc6-4dbf-bfa3-47fe410a577d','6aabf86c-9f75-46a0-9f76-7cfe2953827e',83,'text','Nhìn ở tầng sâu hơn, Radicle không chỉ quyết định tổ chức “làm gì”, mà còn quyết định tổ chức “không làm gì”, dù điều đó có thể đem lại dòng tiền ngắn hạn. Và trong quản trị, chính những giới hạn đạo đức được xác lập rõ ràng ấy mới là thứ định hình bản lĩnh của một thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53760ead-3b0c-46f3-a80a-81fbedc96649','6aabf86c-9f75-46a0-9f76-7cfe2953827e',84,'text','**Kết luận**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('412964e6-4af5-4fe3-87b2-f7bcea3b4a41','6aabf86c-9f75-46a0-9f76-7cfe2953827e',85,'text','Chiếc rễ mầm của một phòng khám không chỉ quyết định hướng đi ban đầu; nó quyết định toàn bộ phẩm chất phát triển về sau. Nếu Radicle yếu, doanh nghiệp có thể vẫn lớn lên về bề ngang nhưng sẽ rỗng ở bên trong. Nếu Radicle đủ sâu, toàn bộ hệ thống sẽ có lực bám để đứng vững trước cạnh tranh, biến động và cám dỗ của tăng trưởng lệch chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90a9c714-b800-400b-8cc7-d7774849dda7','6aabf86c-9f75-46a0-9f76-7cfe2953827e',86,'text','Trong trường hợp của “Nha khoa Bảo tồn”, chiếc rễ mầm ấy không chỉ nhằm cứu những chiếc răng thật. Ở bình diện lớn hơn, nó còn là nỗ lực cứu lại niềm tin dành cho một ngành nghề. Khi một phòng khám dám gọi đúng tên nỗi đau của khách hàng và kiên trì giải quyết nó từ gốc, phòng khám ấy không chỉ đang xây một cơ sở kinh doanh. Nó đang đặt viên đá đầu tiên cho một hệ điều hành chính trực và một di sản nghề nghiệp có khả năng đi rất xa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d025b833-65ad-4f0e-8763-558c6d059b1a','03-roadmap-to-be-sky-test','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',3,'O - Operating Code','o-operating-code',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c5f9d9db-13ac-444a-b9f7-7af47191665d','d025b833-65ad-4f0e-8763-558c6d059b1a',87,'text','***Mã nguồn vận hành - Đỉnh cao của tự vận hành***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13ae3730-7929-4823-9333-56abf7a03dc1','d025b833-65ad-4f0e-8763-558c6d059b1a',88,'text','Nếu **Radicle** trả lời câu hỏi “vì sao tổ chức phải tồn tại”, thì **Operating Code** trả lời câu hỏi “tổ chức sẽ vận hành theo hệ quy chiếu nào để không phản bội lý do tồn tại ấy”. Đây là tầng chuẩn hóa phần mềm tư duy của tổ chức. Nó không chỉ tạo ra sự đồng nhất trong hành vi, mà còn tạo ra sự đồng nhất trong cách hiểu, cách tin, cách ra quyết định và cách giữ khí chất vận hành dưới áp lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b25b9b5-37bf-4642-a2cd-97f6cc0e10a2','d025b833-65ad-4f0e-8763-558c6d059b1a',89,'text','Ở cấp độ Framework, Operating Code được cấu thành bởi **5 trục nền tảng**: **Quy luật – Nguyên lý – Nguyên tắc – Quan niệm – Tâm thái**. Năm trục này đi từ tầng khách quan của thực tại đến tầng chủ quan của nội tâm, từ những điều tổ chức phải hiểu đến những điều tổ chức phải sống. Chúng tạo thành mã nguồn vận hành chung cho toàn bộ hệ thống, bảo đảm rằng từ ghế lâm sàng đến bộ phận gián tiếp, mọi vị trí đều không chỉ làm đúng việc mà còn làm đúng theo cùng một logic.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5aa4d3c2-809b-4a0d-8ce4-c9c6d8c87e3e','d025b833-65ad-4f0e-8763-558c6d059b1a',90,'text','**Quy luật** là những sự thật khách quan đang chi phối tổ chức, bất kể tổ chức có muốn thừa nhận hay không. Đây là tầng giúp doanh nghiệp thoát khỏi ngây thơ vận hành. Khi nắm được quy luật, người lãnh đạo ngừng phản ứng với bề mặt và bắt đầu nhìn thấy căn nguyên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4b064d5-e7b7-43c1-afeb-9108da66c704','d025b833-65ad-4f0e-8763-558c6d059b1a',91,'text','**Câu hỏi cốt lõi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ae0f40d-9ca2-4964-814e-9424b59c50b2','d025b833-65ad-4f0e-8763-558c6d059b1a',92,'text','- Tổ chức này đang bị chi phối bởi những quy luật sống còn nào?- Điều gì luôn đúng trong thực tế vận hành, dù con người có thích hay không?- Những hệ quả nào sẽ tất yếu xảy ra nếu tổ chức làm sai?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0853718f-8a72-4ea6-ad24-88a59563ed42','d025b833-65ad-4f0e-8763-558c6d059b1a',93,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08120bf4-466e-4a1f-9f1e-c42870355d97','d025b833-65ad-4f0e-8763-558c6d059b1a',94,'text','- Niềm tin của bệnh nhân tích lũy chậm nhưng có thể sụp đổ rất nhanh.- Chất lượng chuyên môn sai lệch sẽ để lại hậu quả dài hơn rất nhiều so với lợi ích doanh thu ngắn hạn.- Trải nghiệm bệnh nhân là kết quả của toàn chuỗi điểm chạm, không phải của riêng một cá nhân.- Tăng trưởng càng nhanh, các lỗ hổng ở tầng gốc càng dễ bị phơi bày.- Một tổ chức thiếu chính trực có thể tăng doanh thu ngắn hạn nhưng sẽ hao mòn vốn niềm tin dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3009c30e-2a75-4d9d-a38b-64f2559e37ec','d025b833-65ad-4f0e-8763-558c6d059b1a',95,'text','***Ý nghĩa quản trị:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a29e5954-e820-4ca7-bb83-a3dd051a0d91','d025b833-65ad-4f0e-8763-558c6d059b1a',96,'text','Nắm được quy luật giúp tổ chức thôi ảo tưởng rằng mọi thứ có thể được giải quyết bằng nỗ lực đơn lẻ hay ý chí cá nhân. Nó buộc hệ thống phải khiêm tốn trước thực tế và xây dựng mô hình vận hành phù hợp với bản chất của đời sống, thay vì phù hợp với mong muốn chủ quan của người đứng đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f7e6542-afdb-4f79-9c9c-c1de1f8c73a6','d025b833-65ad-4f0e-8763-558c6d059b1a',97,'text','**Nguyên lý** là những chân lý vận hành nền tảng mà tổ chức lựa chọn làm trục ổn định cho mọi quyết định. Nếu quy luật là cái khách quan đang diễn ra, thì nguyên lý là điều tổ chức chủ động chọn để không bị sống theo tình huống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fed8fd0-ef48-4506-b243-42d53611384d','d025b833-65ad-4f0e-8763-558c6d059b1a',98,'text','**Câu hỏi cốt lõi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8dd4862-410c-486f-849a-6af32446bfb0','d025b833-65ad-4f0e-8763-558c6d059b1a',99,'text','- Chúng ta lấy điều gì làm nền bất biến khi hoàn cảnh thay đổi?- Khi đứng trước xung đột lợi ích, đâu là chân lý dẫn đường?- Điều gì phải luôn đúng trong cách tổ chức này hành động?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b27c30e0-57a1-4474-804b-26f216c63e55','d025b833-65ad-4f0e-8763-558c6d059b1a',100,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e740417b-d56f-4ee3-b77d-9c2d82ed54a2','d025b833-65ad-4f0e-8763-558c6d059b1a',101,'text','- Luôn bảo vệ lợi ích dài hạn của bệnh nhân trước lợi ích doanh thu ngắn hạn.- Luôn xử lý từ gốc thay vì chữa cháy trên bề mặt.- Luôn ưu tiên sự thật chuyên môn hơn sự dễ nghe trong giao tiếp.- Luôn xem niềm tin là tài sản cốt lõi của tổ chức.- Luôn hiểu rằng tăng trưởng đúng phải đi cùng trưởng thành nội lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7316a79-6e27-46ee-808e-37da3c81dd79','d025b833-65ad-4f0e-8763-558c6d059b1a',102,'text','***Ý nghĩa quản trị:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('417c2055-aa83-43ed-a897-83d61f68e4f1','d025b833-65ad-4f0e-8763-558c6d059b1a',103,'text','Nguyên lý tạo ra trục nhất quán cho tổ chức. Khi chưa có nguyên lý, doanh nghiệp thường vận hành theo tâm trạng, áp lực và biến động ngắn hạn. Khi nguyên lý được xác lập rõ, tổ chức bắt đầu có “xương sống nhận thức”, nhờ đó không dễ bị cuốn trôi bởi những lựa chọn tiện lợi nhưng lệch chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b153abb-566b-469c-a52d-c60d8110a02a','d025b833-65ad-4f0e-8763-558c6d059b1a',104,'text','**Nguyên tắc** là sự chuyển hóa của nguyên lý thành các quy ước hành động cụ thể. Nếu nguyên lý trả lời “điều gì luôn đúng”, thì nguyên tắc trả lời “vì điều đúng ấy, trong thực tế chúng ta sẽ hành xử như thế nào”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5ca11e2-e091-4763-8ccc-f995fd7bffe6','d025b833-65ad-4f0e-8763-558c6d059b1a',105,'text','Câu hỏi cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6a14688-50fc-4724-82a1-d8943496ffed','d025b833-65ad-4f0e-8763-558c6d059b1a',106,'text','- Trong các tình huống thường gặp, chúng ta sẽ xử lý theo chuẩn nào?- Điều gì được phép và điều gì không được phép trong vận hành hằng ngày?- Khi các bộ phận phối hợp với nhau, chuẩn hành xử chung là gì?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4d4a4b0-bdbd-44ef-a16b-4f647c44ed3e','d025b833-65ad-4f0e-8763-558c6d059b1a',107,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06fdc507-afca-4d05-881e-0b5b560442e6','d025b833-65ad-4f0e-8763-558c6d059b1a',108,'text','- Không chỉ định quá mức để đổi lấy doanh số.- Không hứa điều chưa chắc chắn về mặt chuyên môn.- Không để bệnh nhân đi qua nhiều điểm chạm mà nhận các thông điệp mâu thuẫn.- Không đẩy lỗi hệ thống cho một cá nhân gánh chịu.- Không ra quyết định lớn khi thiếu dữ liệu và thiếu đối thoại liên chức năng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('846283ca-08f2-44ce-97cc-338d2df6fba5','d025b833-65ad-4f0e-8763-558c6d059b1a',109,'text','***Ý nghĩa quản trị:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49d3e64b-b104-449a-bf43-75eca99cc6e4','d025b833-65ad-4f0e-8763-558c6d059b1a',110,'text','Nguyên tắc giúp tổ chức đi từ tầng nhận thức xuống tầng hành vi. Nó giảm sự tùy hứng trong ra quyết định, tạo ra chuẩn chung để các vị trí khác nhau vẫn có thể phối hợp theo cùng một logic. Đây là lớp trung gian quan trọng nối triết lý với thực thi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dbc1b76-4cc0-460b-b872-2a65982388d9','d025b833-65ad-4f0e-8763-558c6d059b1a',111,'text','**Quan niệm** là cách tổ chức hiểu bản chất của công việc, của khách hàng, của đội ngũ, của tăng trưởng và của chính mình. Đây là tầng định hình thế giới quan vận hành. Nhiều tổ chức có quy trình nhưng vẫn rối loạn vì quan niệm nền tảng bị lệch ngay từ đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('833ed9b8-1425-4977-a80e-96d1bf74f2be','d025b833-65ad-4f0e-8763-558c6d059b1a',112,'text','Câu hỏi cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6b7bbe0-4d27-4c4e-9c1c-e3a39f73c9fb','d025b833-65ad-4f0e-8763-558c6d059b1a',113,'text','- Chúng ta thật sự nhìn bệnh nhân là ai?- Chúng ta hiểu bản chất của tăng trưởng là gì?- Chúng ta nhìn nhân sự như nguồn lực khai thác hay con người cần được dẫn dắt để trưởng thành?- Chúng ta hiểu thương hiệu là hình ảnh hay là lời hứa được thực hiện nhất quán?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10989525-00a2-4b74-9713-0306aedf8fb8','d025b833-65ad-4f0e-8763-558c6d059b1a',114,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40f47ce5-55a1-46cc-9c79-76fcdfbe1387','d025b833-65ad-4f0e-8763-558c6d059b1a',115,'text','- Bệnh nhân không phải “mã doanh thu”, mà là người đang mang nỗi đau và trao niềm tin.- Sai sót không chỉ là lỗi cá nhân, mà còn là dữ liệu để nhìn lại hệ thống.- Nhân sự không chỉ là người làm việc, mà là chủ thể cùng mang giá trị nghề nghiệp.- Tăng trưởng không phải là phình to nhanh, mà là lớn lên mà không đánh mất phẩm chất.- Thương hiệu không nằm ở quảng cáo đẹp, mà nằm ở độ trùng khớp giữa lời hứa và trải nghiệm thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2dee4906-fff9-4ef0-abe5-e5e88f1812d9','d025b833-65ad-4f0e-8763-558c6d059b1a',116,'text','***Ý nghĩa quản trị:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25496f1c-ef2c-458e-978a-e39d7cfcd5d4','d025b833-65ad-4f0e-8763-558c6d059b1a',117,'text','Quan niệm quyết định chiều sâu văn hóa vận hành. Một quan niệm sai sẽ làm mọi tầng phía dưới bị lệch, kể cả khi quy trình được viết rất chỉnh chu. Bởi suy cho cùng, con người hành động lâu dài theo điều họ thật sự tin, không phải theo những gì chỉ được phát biểu cho đúng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b074bb3d-75bd-406c-b666-cce3e4e32f4e','d025b833-65ad-4f0e-8763-558c6d059b1a',118,'text','**Tâm thái** là trạng thái nội tâm mà tổ chức chủ động nuôi dưỡng khi làm việc, phục vụ và ra quyết định. Đây là tầng khí chất (năng lượng) vận hành. Nếu bốn trục trên giúp tổ chức biết phải nghĩ gì và làm gì, thì tâm thái quyết định tổ chức sẽ hiện diện như thế nào trong từng hành động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c09cc542-1474-46ac-8e11-d2cb00995e31','d025b833-65ad-4f0e-8763-558c6d059b1a',119,'text','**Câu hỏi cốt lõi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4695080e-906e-4349-836b-3f8fcb303ad1','d025b833-65ad-4f0e-8763-558c6d059b1a',120,'text','- Chúng ta muốn đội ngũ làm việc với trạng thái nội tâm nào?- Trước áp lực, sai sót, xung đột hay cám dỗ, tổ chức này sẽ giữ tâm thế gì?- Khí chất cốt lõi mà tổ chức muốn bảo tồn là gì?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8904e948-c5b4-4645-959f-e1ca8971bbb2','d025b833-65ad-4f0e-8763-558c6d059b1a',121,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c6cef1b-92d0-42d0-9a3e-0e0d33b4b732','d025b833-65ad-4f0e-8763-558c6d059b1a',122,'text','- Bình tĩnh trước áp lực, không phản ứng hoảng loạn theo sự cố.- Khiêm tốn trước chuyên môn, không tự mãn với kinh nghiệm cũ.- Chính trực trước cám dỗ doanh thu, không bẻ cong chuẩn mực vì lợi ích ngắn hạn.- Tận tâm với bệnh nhân, không làm cho xong việc.- Cầu thị trước sai sót, không đổ lỗi hay phòng thủ bản ngã.- Kiên nhẫn trong xây dựng niềm tin, không nóng vội đòi kết quả tức thời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e39ef7d-bdc8-43bd-b7d8-a869c51bd96e','d025b833-65ad-4f0e-8763-558c6d059b1a',123,'text','***Ý nghĩa quản trị:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9748738c-d177-4644-bacc-908e6b6a7369','d025b833-65ad-4f0e-8763-558c6d059b1a',124,'text','Tâm thái là phần làm nên trạng thái tinh thần của tổ chức. Một hệ thống có thể đúng về quy trình nhưng vẫn thất bại nếu tâm thái vận hành sai lệch: nóng vội, tự mãn, vô cảm hoặc phòng thủ. Vì vậy, muốn tổ chức trưởng thành thật sự, Operating Code phải chạm tới phần nội tâm này, thay vì chỉ dừng ở các quy chuẩn kỹ thuật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6064af23-1645-4fd3-ae56-397b3fa8524c','d025b833-65ad-4f0e-8763-558c6d059b1a',125,'text','**Ma trận 5 trục**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6e19274-f55b-4bbf-80bb-973ac915f81d','d025b833-65ad-4f0e-8763-558c6d059b1a',126,'text','Operating Code không phải là một bộ nội quy mở rộng. Nó là mã nguồn tư duy của tổ chức. Một hệ điều hành chỉ thật sự trưởng thành khi toàn bộ đội ngũ cùng hiểu quy luật, cùng bám nguyên lý, cùng hành xử theo nguyên tắc, cùng chia sẻ một quan niệm đúng về công việc và cùng nuôi dưỡng một tâm thái xứng đáng với sứ mệnh mà mình đang theo đuổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7adb6b52-a085-44e9-9fe5-49057755126d','03-roadmap-to-be-sky-test','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',3,'O - Outreach','o-outreach',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d64efd3-40a9-48ad-bd41-08e05210dbe1','7adb6b52-a085-44e9-9fe5-49057755126d',127,'text','***Biên độ cắm rễ - Tư duy ngược về tầm nhìn (Vision)***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec15277b-e939-4525-bfc2-8797481bb56a','7adb6b52-a085-44e9-9fe5-49057755126d',128,'text','Nếu **Radicle** trả lời câu hỏi tổ chức sinh ra để làm gì, và **Operating Code** xác lập cách tổ chức phải vận hành để trung thành với lý do tồn tại ấy, thì **Outreach** trả lời một câu hỏi khác ở tầng phát triển: tổ chức này muốn vươn xa đến đâu, và từ hôm nay phải mở rộng phần gốc ngầm đến biên độ nào để chống đỡ được tương lai đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf6dee08-8ca0-447b-ba23-52edbdecbd93','7adb6b52-a085-44e9-9fe5-49057755126d',129,'text','Trong logic của R.O.A.D.M.A.P, **Outreach** chính là cách diễn giải lại khái niệm **Vision** dưới một ngôn ngữ hữu cơ hơn. Tầm nhìn không được hiểu như một bức tranh viễn tưởng đẹp đẽ, càng không phải một con số doanh thu treo trước mắt để kích thích ý chí. Ở cấp độ quản trị trưởng thành, tầm nhìn là sự xác định trước **biên độ phát triển tương lai** và đồng thời là cam kết mở rộng **năng lực chịu tải ở tầng gốc** để tương xứng với biên độ ấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c17ba34-b813-41d3-bce5-81c0618d0ff3','7adb6b52-a085-44e9-9fe5-49057755126d',130,'text','Trong quy luật sinh học, không có cái cây nào có thể sở hữu một tán lớn mà lại mang một bộ rễ nhỏ. Tán cây muốn vươn rộng bao nhiêu mét, bộ rễ dưới đất phải lan rộng ít nhất với biên độ tương ứng để giữ cân bằng, hút đủ dưỡng chất và chống chịu được gió bão. Nếu phần trên phát triển quá nhanh so với phần dưới, cây có thể trông rất mạnh trong điều kiện bình thường nhưng sẽ bật gốc ngay khi gặp một cú va đập đủ lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('110a8c34-417d-48f6-acd0-31b794c83c5f','7adb6b52-a085-44e9-9fe5-49057755126d',131,'text','Tổ chức cũng như vậy. Rất nhiều doanh nghiệp thất bại không phải vì thiếu khát vọng mở rộng, mà vì tầm nhìn của họ chỉ phình ra ở phần “tán cây” - doanh thu, chi nhánh, thương hiệu, quy mô - trong khi phần “rễ ngầm” lại không được chuẩn bị tương xứng. Họ muốn tăng trưởng nhanh nhưng chưa chuẩn hóa SOP. Họ muốn giữ bác sĩ giỏi nhưng chưa có khung năng lực và cơ chế đãi ngộ đủ công bằng. Họ muốn điều hành theo dữ liệu nhưng thông tin vẫn nằm rải rác trên giấy tờ, file cá nhân hoặc trí nhớ của từng người.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38578b78-c228-44ac-9e6a-a37cf33588b2','7adb6b52-a085-44e9-9fe5-49057755126d',132,'text','Chính vì vậy, cần có Outreach. Tầng này buộc người lãnh đạo phải nhìn tầm nhìn như một bài toán năng lực chịu tải, không phải như một bài toán mơ ước. Nó chuyển câu hỏi từ “ta muốn lớn đến đâu?” sang “ta phải chuẩn bị phần gốc ngầm đến mức nào để xứng đáng với độ lớn đó?”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c94c407f-1b41-4920-b65d-adac66fee251','7adb6b52-a085-44e9-9fe5-49057755126d',133,'text','**Không phải mơ lớn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10181062-9ff9-40fc-bb63-4edf01643940','7adb6b52-a085-44e9-9fe5-49057755126d',134,'text','Một trong những ngộ nhận phổ biến nhất về Vision là đồng nhất nó với tham vọng. Nhưng tham vọng chỉ là năng lượng kéo tổ chức tiến về phía trước; còn **Outreach** mới là phần đo lường mức độ chuẩn bị để tương lai ấy có thể đứng vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1eed3c7f-2d0d-4d67-b8c2-a687114315e9','7adb6b52-a085-44e9-9fe5-49057755126d',135,'text','Nói cách khác, Outreach không hỏi tổ chức muốn sở hữu điều gì, mà hỏi tổ chức phải mở rộng trước những gì ở tầng nền để không bị tương lai nuốt chửng. Vì thế, Outreach là một dạng Vision mang tính cấu trúc: nó quy định ngay từ hiện tại biên độ mà hệ thống rễ ngầm phải cắm ra, bao gồm quy trình, năng lực con người, năng lực điều hành, hệ thống dữ liệu, công nghệ quản trị, cấu trúc phối hợp và khả năng chuẩn hóa tri thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4feea74c-bab7-462e-b46d-e0f6d0b015e5','7adb6b52-a085-44e9-9fe5-49057755126d',136,'text','Ở đây, tầm nhìn không còn là một khẩu hiệu đầy cảm hứng. Nó trở thành một cam kết rất cụ thể: nếu 3 đến 5 năm tới tổ chức muốn có một “tán cây” lớn hơn, thì ngay hôm nay phải mở rộng phần gốc đến đúng biên độ tương xứng. Không có ngoại lệ cho quy luật này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eccfb0e5-a111-484b-8308-f6ea6dfc3dcb','7adb6b52-a085-44e9-9fe5-49057755126d',137,'text','Ở cấp độ ứng dụng, Outreach không đo bằng cảm xúc mà đo bằng năng lực nền cần phải hình thành trước khi tổ chức bước vào một quy mô mới. Thông thường, biên độ cắm rễ của một phòng khám hoặc chuỗi nha khoa sẽ phải được nhìn qua ít nhất năm lớp chuẩn bị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59d6e734-7aaf-4c03-ac73-d29a52f0bf3b','7adb6b52-a085-44e9-9fe5-49057755126d',138,'text','**1. Biên độ quy trình**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('419153d5-531c-4cb2-bd57-b9e8b99880f2','7adb6b52-a085-44e9-9fe5-49057755126d',139,'text','Tổ chức phải xác định mức độ chuẩn hóa vận hành cần đạt để chịu được quy mô tương lai. Điều này bao gồm SOP lâm sàng, SOP tư vấn, SOP chăm sóc khách hàng, SOP giao ban, SOP xử lý sự cố và SOP kiểm soát chất lượng. Nếu quy trình chưa được đóng gói, tổ chức càng mở rộng càng tăng độ lệch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6d8c066-fae4-4d49-b485-75617661494d','7adb6b52-a085-44e9-9fe5-49057755126d',140,'text','**2. Biên độ năng lực con người**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d58cad8-a1da-4c94-aa73-2645adc9292c','7adb6b52-a085-44e9-9fe5-49057755126d',141,'text','Tầm nhìn mở rộng chỉ có ý nghĩa khi đội ngũ đủ sức gánh nó. Outreach ở tầng này đòi hỏi phải làm rõ khung năng lực cho từng vị trí, cơ chế đánh giá, lộ trình phát triển nghề nghiệp và hệ thống đãi ngộ đủ tốt để thu hút và giữ chân đúng người. Một tầm nhìn lớn không thể đứng trên một đội ngũ mơ hồ về vai trò và bất an về tương lai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6277551e-3462-4e09-a304-5be371701a4e','7adb6b52-a085-44e9-9fe5-49057755126d',142,'text','**3. Biên độ dữ liệu và công nghệ quản trị**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f00fdf58-8df5-4b91-83ad-20921df4db81','7adb6b52-a085-44e9-9fe5-49057755126d',143,'text','Khi quy mô tăng lên, trí nhớ cá nhân và quản lý cảm tính sẽ nhanh chóng sụp đổ. Vì vậy, Outreach phải bao gồm cả việc số hóa dữ liệu, chuẩn hóa dashboard, xây dựng cơ chế theo dõi KPI, đồng bộ luồng thông tin liên phòng ban và hình thành hạ tầng quản trị dựa trên dữ liệu. Không có dữ liệu chuẩn, tăng trưởng sẽ sớm biến thành hỗn loạn có quy mô lớn hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('378043f1-b21b-4ba5-beeb-a399cace4b66','7adb6b52-a085-44e9-9fe5-49057755126d',144,'text','**4. Biên độ phối hợp hệ thống**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('720f6a4d-b433-4853-8f31-abb1d3c0662f','7adb6b52-a085-44e9-9fe5-49057755126d',145,'text','Một phòng khám nhỏ có thể vận hành dựa nhiều vào cá nhân chủ chốt, nhưng một hệ thống muốn mở rộng bắt buộc phải học cách vận hành theo cấu trúc. Outreach vì thế phải đo cả khả năng phối hợp giữa các bộ phận, khả năng phân quyền, chất lượng bàn giao, năng lực quản lý trung gian và mức độ phụ thuộc vào founder. Nếu tán cây lớn dần mà bộ rễ vẫn chỉ hút dinh dưỡng qua một điểm, sụp đổ là điều tất yếu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3e75a13-3753-41da-b3ad-11b7739b722c','7adb6b52-a085-44e9-9fe5-49057755126d',146,'text','**5. Biên độ văn hóa và bản sắc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3293a22-2046-4795-84f5-7cb3e6f7d3ea','7adb6b52-a085-44e9-9fe5-49057755126d',147,'text','Mở rộng không chỉ là nhân bản cơ sở vật chất, mà còn là nhân bản bản sắc. Nếu phòng khám muốn đi xa, Outreach phải bao gồm việc đóng gói được văn hóa phục vụ, triết lý chuyên môn và chuẩn hành xử cốt lõi để khi tổ chức mở thêm người, thêm điểm chạm hay thêm chi nhánh, phần hồn ban đầu không bị pha loãng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3bdeb7c-9b18-4bfb-b07a-8565149c4ab8','7adb6b52-a085-44e9-9fe5-49057755126d',148,'text','*Ví dụ ứng dụng*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13ef3869-ff66-46e4-9343-5f739ab76ec7','7adb6b52-a085-44e9-9fe5-49057755126d',149,'text','Giả sử mục tiêu 3 năm tới của một phòng khám là mở rộng quy mô vận hành, gia tăng năng lực phục vụ và sẵn sàng bước sang mô hình đa cơ sở. Nếu chỉ diễn đạt tầm nhìn theo kiểu “trở thành chuỗi nha khoa hàng đầu” hoặc “đạt mức doanh thu X”, đó mới chỉ là phần tán cây được tưởng tượng ra ở phía trên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d8c2ce4-dc60-49bd-98ec-22ed5246e13e','7adb6b52-a085-44e9-9fe5-49057755126d',150,'text','Câu hỏi của Outreach sẽ khác. Nó buộc tổ chức phải trả lời: để chống đỡ được quy mô ấy, phần rễ ngầm phải được cắm rộng đến đâu ngay từ bây giờ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e74c7500-61b3-4afa-b9e8-068d961c6098','7adb6b52-a085-44e9-9fe5-49057755126d',151,'text','Trong trường hợp này, Outreach của giai đoạn 3 năm có thể được cụ thể hóa thành ba nhiệm vụ nền tảng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('74482fc2-9693-46b2-bedd-b1964ffb22da','7adb6b52-a085-44e9-9fe5-49057755126d',152,'text','- **Đóng gói hoàn chỉnh 100% hệ thống SOP lâm sàng và vận hành cốt lõi**, để tri thức không còn phụ thuộc vào cá nhân và có thể nhân rộng mà không làm lệch chuẩn.- **Hoàn thiện khung năng lực và cơ chế đãi ngộ tự động hóa**, ví dụ một file Excel hoặc hệ thống quản trị đủ thông minh để đánh giá năng lực, tính lương và giữ chân bác sĩ giỏi một cách minh bạch, công bằng.- **Chuyển đổi số toàn bộ dữ liệu quản trị**, từ dữ liệu bệnh nhân, vận hành, tài chính đến dữ liệu nhân sự, để việc ra quyết định không còn dựa trên cảm giác hay sự chắp vá thủ công.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('887ae8a3-36bf-4114-b6fe-5499425e3741','7adb6b52-a085-44e9-9fe5-49057755126d',153,'text','Nhìn theo logic này, Outreach không phải là mục tiêu “mở rộng phòng khám”, mà là **biên độ chuẩn bị của bộ rễ** để việc mở rộng ấy không làm bật gốc hệ thống khi gặp áp lực thị trường, sai lệch vận hành hoặc biến động nhân sự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('113422be-de71-450a-bd70-2bbfea9f5cff','7adb6b52-a085-44e9-9fe5-49057755126d',154,'text','Ở tầng chiến lược, Outreach mang lại ít nhất bốn giá trị rất quan trọng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0627dc31-c0f5-4489-80c6-525293fa566a','7adb6b52-a085-44e9-9fe5-49057755126d',155,'text','- **Biến tầm nhìn thành năng lực chuẩn bị**: giúp tổ chức ngừng mơ theo cảm hứng và bắt đầu xây nền theo logic chịu tải.- **Ngăn tăng trưởng vượt quá sức chứa**: tránh tình trạng phần trên phình to quá nhanh trong khi phần dưới chưa đủ sức chống đỡ.- **Định hướng đầu tư đúng chỗ**: thay vì chỉ đầu tư vào mặt tiền tăng trưởng, tổ chức biết phải ưu tiên nguồn lực cho SOP, con người, dữ liệu và cấu trúc quản trị.- **Giảm rủi ro bật gốc khi gặp biến động**: một hệ thống rễ đủ rộng sẽ hấp thụ sốc tốt hơn khi đối diện với khủng hoảng nhân sự, lỗi chuyên môn, áp lực dòng tiền hoặc biến động thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a08d171d-8317-47a6-9bdb-c6f16d925546','7adb6b52-a085-44e9-9fe5-49057755126d',156,'text','Nói ngắn gọn, Outreach là tầng khiến Vision trở nên có trách nhiệm. Nó nhắc người lãnh đạo rằng quyền được mơ lớn luôn đi kèm nghĩa vụ phải cắm rễ sâu hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bea77af-c179-47ed-9ea1-d267dd38a9e1','7adb6b52-a085-44e9-9fe5-49057755126d',157,'text','Outreach là biên độ cắm rễ của tầm nhìn. Nó buộc tổ chức phải hiểu rằng tương lai không được chống đỡ bằng ý chí, mà bằng năng lực nền được chuẩn bị từ sớm. Muốn có một tán cây lớn hơn trong 3 đến 5 năm tới, phòng khám phải mở rộng trước phần rễ ngầm của mình: quy trình, con người, dữ liệu, công nghệ quản trị, cấu trúc phối hợp và bản sắc vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc320826-041b-45e4-8390-1da54aae7a09','03-roadmap-to-be-sky-test','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',3,'T - Tenacity','t-tenacity',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff560c2c-af5a-43f8-90fe-3b1f79b3fa33','dc320826-041b-45e4-8390-1da54aae7a09',158,'text','***Khí chất và giá trị cốt lõi - Sức mạnh vô hình không thể khuất phục***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b5805ca7-4cb4-4f71-b6af-216a4f3e16e4','dc320826-041b-45e4-8390-1da54aae7a09',159,'text','Nếu **Radicle** trả lời câu hỏi tổ chức sinh ra để làm gì, **Operating Code** xác lập hệ quy chiếu vận hành, và **Outreach** mở ra biên độ phát triển của tương lai, thì **Tenacity** đi thẳng vào một tầng khác: tổ chức này muốn được cấu thành bởi những con người mang khí chất gì.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86860f24-a47f-47ff-a91c-d47a112bd01d','dc320826-041b-45e4-8390-1da54aae7a09',160,'text','Đây là tầng nói về **tính cách cốt lõi của con người trong hệ thống**. Không phải kỹ năng, không phải vai trò, cũng không phải hiệu suất trước mắt, mà là phẩm chất nội tại quyết định cách mỗi cá nhân phản ứng trước áp lực, chướng ngại, sự thật khó nghe, sai sót nghề nghiệp và trách nhiệm với người khác. Khi những phẩm chất ấy được lặp đi lặp lại trong đủ nhiều con người, chúng không còn là tính cách cá nhân nữa; chúng tạo thành **cá tính của tổ chức**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('745e2f6a-e9b8-412b-96b0-aa76b27ffbe7','dc320826-041b-45e4-8390-1da54aae7a09',161,'text','Vì vậy, Tenacity đồng thời là hai thứ: **Core Characters** và **Core Values**. Nó vừa là khí chất mà từng cá nhân phải có để được xem là phù hợp với đội ngũ; vừa là bộ giá trị cốt lõi mà tổ chức theo đuổi, được diễn đạt bằng những từ đơn giản nhưng phải được định nghĩa rõ ràng để mọi người cùng hiểu giống nhau, sống giống nhau và đo mình theo cùng một chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e04c9b3-c684-4d72-8512-9fa75f173529','dc320826-041b-45e4-8390-1da54aae7a09',162,'text','Trong tự nhiên, khi rễ cây đâm xuống lòng đất và gặp đá tảng, nó không quay đầu và cũng không tự gãy nát. Nó tìm đường khác, luồn qua khe nhỏ, bám vào từng khoảng hở, mài dần vật cản để tiếp tục đi xuống. Sức mạnh ấy không ồn ào, nhưng bền bỉ. Nó không hung hăng, nhưng không bỏ cuộc. Đó chính là hình ảnh gần nhất để nói về **Tenacity**: sự lì lợm có kỷ luật, sự dẻo dai có định hướng và khả năng giữ vững đường đi dù thực tại không thuận lợi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a1f0081-03ec-4aa8-80f9-dd9a39f2d470','dc320826-041b-45e4-8390-1da54aae7a09',163,'text','Trong môi trường phòng khám, khí chất này có ý nghĩa đặc biệt. Bởi tổ chức không chỉ đối diện với lịch hẹn, doanh thu hay chỉ số vận hành. Tổ chức còn đối diện với những thứ khó hơn nhiều: sai sót lâm sàng, bệnh nhân mất niềm tin, khiếu nại căng thẳng, áp lực phối hợp nội bộ, mâu thuẫn giữa đúng chuyên môn và dễ kiếm tiền, mệt mỏi cảm xúc và sức ép giữ chuẩn trong lúc thị trường ngày càng xô lệch. Những lúc như vậy, kỹ năng chỉ giải quyết được một phần. Phần còn lại phụ thuộc vào khí chất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebf3a6e7-2324-4557-acff-632c49d1fad3','dc320826-041b-45e4-8390-1da54aae7a09',164,'text','Tenacity vì thế là tầng giúp tổ chức trả lời câu hỏi: khi gặp sức ép, đội ngũ này sẽ **co rúm lại**, **lấp liếm đi**, **đổ lỗi cho nhau**, hay sẽ **nhìn thẳng vào sự thật và đi tiếp bằng bản lĩnh**?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1af701cf-e2fe-4349-9397-52556e12a3b6','dc320826-041b-45e4-8390-1da54aae7a09',165,'text','Tenacity không nên bị hiểu hẹp như “cố gắng đến cùng” hay “chịu khó làm việc”. Trong bối cảnh xây tổ chức, Tenacity là một cấu trúc khí chất gồm nhiều phẩm chất đi cùng nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a10a645-a904-4cde-b686-3f1929a39c79','dc320826-041b-45e4-8390-1da54aae7a09',166,'text','Nó bao gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14521b20-1f0a-414f-bce5-279a0b6d3f01','dc320826-041b-45e4-8390-1da54aae7a09',167,'text','- **Lì lợm trước khó khăn** nhưng không cố chấp mù quáng.- **Dẻo dai trước áp lực** nhưng không đánh mất chuẩn mực.- **Thẳng thắn trước sự thật** nhưng không thô ráp hay làm tổn thương người khác.- **Dám nhận trách nhiệm** nhưng không tự vệ bằng đổ lỗi.- **Kiên định với điều đúng** dù phải trả giá ngắn hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('deecf820-6471-4675-9c80-2278b0a9a782','dc320826-041b-45e4-8390-1da54aae7a09',168,'text','Ở tầng này, tổ chức bắt đầu định nghĩa rất rõ: người như thế nào thì phù hợp để đi cùng, và người như thế nào dù giỏi đến đâu cũng không thể trở thành một phần bền vững của hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f56bc48b-319a-47b4-bf91-66d4564d1c5b','dc320826-041b-45e4-8390-1da54aae7a09',169,'text','Không có tổ chức nào có cá tính riêng nếu đội ngũ bên trong là tập hợp rời rạc của những con người mang khí chất đối nghịch nhau. Một phòng khám muốn có bản sắc rõ không thể tuyển một bác sĩ trung thực, một lễ tân lấp liếm, một quản lý né trách nhiệm, một tư vấn viên chỉ giỏi ép chốt và một founder lại luôn nói về chính trực. Trong trường hợp đó, thương hiệu chỉ còn là lớp sơn bên ngoài; bên trong không có cá tính thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('129fc8d6-fa7f-465d-b2e1-3cc427f01db0','dc320826-041b-45e4-8390-1da54aae7a09',170,'text','Tenacity là tầng tạo ra sự thống nhất về khí chất. Nó làm rõ rằng cá tính của tổ chức không được dựng nên bằng khẩu hiệu thương hiệu, mà bằng những phẩm chất được lặp lại trong hành vi hằng ngày của đội ngũ. Nếu đủ nhiều người trong cùng một hệ thống đều nói thật, đứng thẳng trước sai sót, không thao túng bệnh nhân, không bỏ cuộc trước áp lực và vẫn giữ được chuẩn nghề nghiệp khi thị trường xô lệch, thì chính những phẩm chất ấy sẽ trở thành “thương hiệu sống” của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ae322c3-11b9-4e9c-bce9-d5417090a712','dc320826-041b-45e4-8390-1da54aae7a09',171,'text','Nói cách khác, Tenacity là phần biến giá trị cốt lõi từ chữ viết thành khí chất nhận diện được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71c82271-2012-4c3f-8b4d-9c2dd9c6a0bf','dc320826-041b-45e4-8390-1da54aae7a09',172,'text','Một lỗi phổ biến khi xây Core Values là dùng những từ rất đẹp như “chính trực”, “tận tâm”, “chuyên nghiệp”, “trách nhiệm”, nhưng không định nghĩa cụ thể. Kết quả là ai cũng tưởng mình hiểu, nhưng mỗi người lại sống theo một nghĩa khác nhau. Khi đó, giá trị cốt lõi chỉ còn là lớp ngôn ngữ trang trí, không đủ sức làm chuẩn cho tuyển dụng, đánh giá hay ra quyết định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24e48219-7a8c-4222-8a34-04d0f566be0b','dc320826-041b-45e4-8390-1da54aae7a09',173,'text','Vì vậy, ở tầng Tenacity, các giá trị cốt lõi nên được diễn đạt bằng **những từ ngắn, dễ nhớ, đời thường**, nhưng nhất định phải được gắn với một định nghĩa vận hành rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('948ad759-a545-4834-bddd-51eec08fece4','dc320826-041b-45e4-8390-1da54aae7a09',174,'text','Ví dụ, một bộ Tenacity có thể gồm những từ như:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('863d195d-ec61-4285-8e89-d5ea32c05249','dc320826-041b-45e4-8390-1da54aae7a09',175,'text','- **Thẳng**: nói đúng sự thật, không vòng vo để lấy lòng, không bóp méo thông tin để chốt sale.- **Lì**: gặp áp lực không bỏ cuộc, gặp sự cố không né tránh, gặp phản hồi khó không co rúm lại.- **Sạch**: không kiếm tiền bằng cách bẻ cong y đức, không lấp liếm sai sót, không làm điều khuất tất sau lưng bệnh nhân.- **Chắc**: làm gì cũng có căn cứ, có kiểm chứng, có trách nhiệm và có độ tin cậy.- **Tử tế**: giao tiếp bằng sự tôn trọng, nhìn bệnh nhân như con người chứ không như hợp đồng doanh thu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23eb435a-a1f3-4eab-be90-eacd4e146619','dc320826-041b-45e4-8390-1da54aae7a09',176,'text','Khi các giá trị được viết như vậy, tổ chức mới có thể dùng chúng như tiêu chuẩn thật cho tuyển người, huấn luyện, phản hồi, đánh giá và giữ chuẩn văn hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c69ec9c-2837-4ba9-b6fe-e88c6ee0d13d','dc320826-041b-45e4-8390-1da54aae7a09',177,'text','**1. Khí chất chuyên gia thẳng thắn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6966be25-e885-49dc-900d-5344e638f32f','dc320826-041b-45e4-8390-1da54aae7a09',178,'text','Một phòng khám có Tenacity không giao tiếp với thị trường bằng giọng điệu thảo mai hoặc kỹ thuật thao túng cảm xúc. Họ cũng không dùng sự sợ hãi của bệnh nhân làm công cụ ép chốt sale. Thay vào đó, họ chọn cách nói thật, nói rõ và nói sao cho người nghe hiểu được bản chất vấn đề mà không bị dọa nạt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ca43bfe-6374-4b7a-b7de-2a9d16547d6a','dc320826-041b-45e4-8390-1da54aae7a09',179,'text','Điều này đòi hỏi đội ngũ phải có khí chất của một **chuyên gia thẳng thắn**. Nghĩa là không lấy thuật ngữ làm quyền lực, không lấy mơ hồ làm công cụ, và không lấy sự hoảng sợ của bệnh nhân để thúc đẩy quyết định tài chính. Người làm nghề phải biết “dịch” ngôn ngữ chuyên môn sang ngôn ngữ đời thường để bệnh nhân hiểu và lựa chọn trong trạng thái sáng suốt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7386deef-52bf-42f3-881c-3f56e8295095','dc320826-041b-45e4-8390-1da54aae7a09',180,'text','*Ví dụ*, thay vì nói “tiêu xương ổ răng do viêm nha chu trầm trọng”, bác sĩ hoặc tư vấn viên có thể nói: “Phần đất giữ chân răng đang bị lở, mình cần xử lý sạch và gia cố lại để răng không bị lung lay thêm.” Đó không phải là cách nói kém chuyên môn; ngược lại, đó là biểu hiện của chuyên môn đủ sâu để nói cho người khác hiểu mà không làm họ thấy mình bị áp đảo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b94b31db-2227-4a93-9df9-3d96745c8f7e','dc320826-041b-45e4-8390-1da54aae7a09',181,'text','**2. Khí chất lì lợm trước sự cố**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2ae891c-c80e-4bb7-b7a4-b1517d02d105','dc320826-041b-45e4-8390-1da54aae7a09',182,'text','Biểu hiện thứ hai của Tenacity nằm ở cách tổ chức phản ứng khi mọi thứ không đi đúng kế hoạch. Một hệ thống yếu khí chất sẽ có xu hướng giấu sai, né trách nhiệm, lấp liếm với khách hàng và đẩy lỗi xuống mắt xích thấp nhất như phụ tá, lễ tân hoặc bộ phận chăm sóc khách hàng. Một hệ thống có Tenacity thì ngược lại: nhìn thẳng vào sự thật, giữ bình tĩnh, xác định trách nhiệm và xử lý theo đúng giao thức đạo đức nghề nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08da30ec-49fe-4fcf-b644-dedb8468be93','dc320826-041b-45e4-8390-1da54aae7a09',183,'text','Trong môi trường lâm sàng, điều này đặc biệt quan trọng. Khi xảy ra sai sót chuyên môn hoặc khách hàng khiếu nại, đội ngũ không được phép phản xạ bằng tự vệ bản ngã. Bác sĩ phải đủ bản lĩnh để đứng ra nhận trách nhiệm trong phạm vi chuyên môn của mình. Quản lý phải đủ vững để bảo vệ sự thật thay vì bảo vệ hình ảnh giả tạo. Tổ chức phải đủ sạch để đặt lợi ích bệnh nhân và sự chính trực lên trên tâm lý giữ thể diện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a27105b6-561c-42a0-a178-4775639748eb','dc320826-041b-45e4-8390-1da54aae7a09',184,'text','Tenacity ở đây không phải là lì để chống chế. Nó là lì để đứng vững trong sự thật, không trốn chạy khỏi hậu quả do chính mình tạo ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73e3a568-e0d8-4e8a-bb4a-2463c18e57d8','dc320826-041b-45e4-8390-1da54aae7a09',185,'text','Ở tầng quản trị, Tenacity mang lại ít nhất bốn giá trị lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be91d2cc-6711-422b-afb3-2df6101c94d5','dc320826-041b-45e4-8390-1da54aae7a09',186,'text','- **Làm rõ tiêu chuẩn con người phù hợp**: tổ chức không chỉ tuyển người có kỹ năng, mà tuyển người có khí chất phù hợp với đường dài.- **Tạo bản sắc đội ngũ**: khi các phẩm chất cốt lõi được lặp lại đủ nhiều, chúng trở thành cá tính thật của tổ chức.- **Tăng sức chống chịu văn hóa**: đội ngũ ít bị tan rã khi gặp khủng hoảng, vì họ có cùng một chuẩn phản ứng trước áp lực.- **Bảo vệ thương hiệu từ bên trong**: thương hiệu không còn phụ thuộc hoàn toàn vào truyền thông, mà được chống đỡ bởi khí chất thật của con người bên trong hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb431a5f-ff0e-4b6e-a073-282072070543','dc320826-041b-45e4-8390-1da54aae7a09',187,'text','Nói cách khác, Tenacity là tầng giúp tổ chức trả lời câu hỏi: **chúng ta không chỉ làm điều gì, mà chúng ta là kiểu người như thế nào khi làm điều đó?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3895a4fd-3ef5-47fa-94d7-a577cf5c0d9e','dc320826-041b-45e4-8390-1da54aae7a09',188,'text','Tenacity là phần định hình Core Characters và Core Values của tổ chức. Nó không nói về kỹ thuật, mà nói về khí chất và giá trị. Nó xác định những phẩm chất mà một cá nhân phải có nếu muốn thực sự trở thành thành viên của hệ thống, đồng thời tạo nên cá tính riêng mà tổ chức mang ra đối diện với thị trường, với khủng hoảng và với chính những thử thách bên trong mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1cad3c50-3751-4733-aa6c-7342fa29b913','03-roadmap-to-be-sky-test','79eb2432-6f77-45ed-a0ad-8fc15c81c03d',3,'S - Standardized Statement','s-standardized-statement',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('424f52c8-f37f-457e-b7dc-d1261a929f4d','1cad3c50-3751-4733-aa6c-7342fa29b913',189,'text','***Tuyên ngôn tiêu chuẩn của tổ chức - Lời nói hiệu triệu lòng người***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d1e7f271-5c84-4c29-bb52-726b1ba163d1','1cad3c50-3751-4733-aa6c-7342fa29b913',190,'text','Nếu **Radicle** là lý do khai sinh, **Operating Code** là mã nguồn vận hành, **Outreach** là biên độ cắm rễ cho tương lai, và **Tenacity** là khí chất cốt lõi của con người trong hệ thống, thì **Standardized Statement** là điểm hội tụ nơi toàn bộ những yếu tố ấy được nén lại thành một tuyên ngôn danh tính ngắn gọn, rõ ràng và không thể dịch chuyển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04bf23e1-06cd-43d3-b1ce-f3e543b5e5df','1cad3c50-3751-4733-aa6c-7342fa29b913',191,'text','Đây không phải là một câu Slogan quảng cáo, càng không phải một đoạn ngôn ngữ trang trí cho đẹp thương hiệu. Ở cấp độ quản trị, Standardized Statement là **tuyên ngôn chuẩn hóa danh tính tổ chức**. Nó là phần kết tinh cô đọng nhất của toàn bộ lớp rễ nền: lý do tồn tại, cách vận hành, biên độ phát triển và khí chất con người. Khi bốn yếu tố ấy được phối trộn đủ chặt, chúng tạo ra một “vết hằn” trong lòng đất, một chuẩn nhận diện mà tổ chức có thể lặp đi lặp lại mà không lệch, nói đi nói lại mà không mệt mỏi, dùng đi dùng lại mà không sai trong mọi điểm chạm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e74ea432-3cc4-4b58-a48f-b9c5073a798c','1cad3c50-3751-4733-aa6c-7342fa29b913',192,'text','Một tổ chức có thể có sứ mệnh đúng, mã vận hành rõ, tầm nhìn đủ sâu và khí chất đội ngũ tốt, nhưng nếu không cô đọng được tất cả thành một tuyên ngôn danh tính thống nhất, thì các tầng ý tưởng ấy vẫn rất dễ bị phân mảnh trong thực tế. Người sáng lập hiểu một kiểu, quản lý diễn giải một kiểu, nhân sự mới nhớ một kiểu, đội marketing viết một kiểu, còn bộ phận vận hành lại sống theo một kiểu khác. Khi đó, tổ chức có nền nhưng không có câu nói chung để khóa nền đó lại thành bản sắc nhất quán.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b1d44e5-8122-4b09-ad3a-d351f34375bf','1cad3c50-3751-4733-aa6c-7342fa29b913',193,'text','Standardized Statement được tạo ra để giải quyết chính điểm đứt gãy này. Nó là một **câu nói chuẩn**, đủ ngắn để ghi nhớ, đủ rõ để lặp lại, đủ sâu để đại diện và đủ chuẩn để trở thành “khuôn nhận diện” cho toàn bộ hệ thống. Mục tiêu của tầng này không phải là gây ấn tượng, mà là tạo ra **sự đồng thanh trong bản sắc**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('078083dd-0946-4d96-b78d-206775f36c17','1cad3c50-3751-4733-aa6c-7342fa29b913',194,'text','Trong hệ điều hành tổ chức, Standardized Statement có ít nhất bốn vai trò nền tảng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df436cf0-bf27-44f0-b21e-f1da2f2e17e1','1cad3c50-3751-4733-aa6c-7342fa29b913',195,'text','- **Khóa lại danh tính tổ chức**: giúp toàn bộ đội ngũ luôn quay về cùng một định nghĩa cốt lõi về mình.- **Chuẩn hóa thông điệp onboarding**: nhân sự mới ngay từ ngày đầu đã biết mình đang bước vào một hệ thống như thế nào.- **Làm chuẩn cho tài liệu nội bộ**: có thể đặt ở trang đầu sổ tay nhân viên, handbook đào tạo, tài liệu văn hóa và các module định hướng.- **Làm kim chỉ nam cho truyền thông đối ngoại**: mọi nội dung trên website, TikTok, Facebook hoặc các điểm chạm thương hiệu khác đều phải phản ánh cùng một tuyên ngôn gốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc91887e-843a-444d-aee1-9464bd3eca8d','1cad3c50-3751-4733-aa6c-7342fa29b913',196,'text','Điều này đặc biệt quan trọng với các phòng khám hoặc chuỗi nha khoa đang muốn xây thương hiệu bền vững. Bởi thương hiệu không chỉ được tạo bởi hình ảnh, màu sắc hay nội dung truyền thông. Thương hiệu được tạo bởi sự lặp lại nhất quán của cùng một bản sắc qua đủ nhiều điểm chạm. Nếu không có một tuyên ngôn tiêu chuẩn làm trục, mỗi điểm chạm sẽ nói một thứ khác nhau, và thương hiệu sẽ bị loãng từ bên trong.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c8e81d3-697b-41f1-862b-15714e4c31b1','1cad3c50-3751-4733-aa6c-7342fa29b913',197,'text','Một Standardized Statement đúng nghĩa không nên dài dòng, cũng không nên tham nhồi nhét tất cả vào một câu. Nó phải ngắn đến mức người mới có thể nhớ sau vài lần đọc, nhưng đủ chặt để nói lên bốn thành phần cốt lõi đã được xây ở các tầng trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48a80135-1bbf-481a-937c-4543dc1aa760','1cad3c50-3751-4733-aa6c-7342fa29b913',198,'text','Về nguyên tắc, một tuyên ngôn tiêu chuẩn tốt nên phản ánh được:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92347629-8f70-4d94-83ef-b707c8b19913','1cad3c50-3751-4733-aa6c-7342fa29b913',199,'text','- **Chúng ta là ai? ** -> danh tính tổ chức.- **Chúng ta vận hành bằng điều gì?** -> logic và tiêu chuẩn hành động.- **Chúng ta ở đây để làm gì?** -> nỗi đau hoặc giá trị cốt lõi mà tổ chức giải quyết.- **Chúng ta mang khí chất nào?** -> phẩm chất tinh thần và đạo đức của đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bca59f17-8b4a-4eb7-b149-9fe1be9262b7','1cad3c50-3751-4733-aa6c-7342fa29b913',200,'text','Khi một câu tuyên ngôn trả lời được bốn lớp này trong một cấu trúc ngắn gọn, nó sẽ có giá trị như một “mã lệnh ngôn ngữ”. Chỉ cần lặp lại đúng câu đó, toàn hệ thống sẽ được kéo về cùng một tâm thế và cùng một chuẩn danh tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('382221b1-c818-4e42-99b7-14429fb6192e','1cad3c50-3751-4733-aa6c-7342fa29b913',201,'text','Ví dụ',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99b3fd9a-4295-4439-948d-255044f99254','1cad3c50-3751-4733-aa6c-7342fa29b913',202,'text','Dựa trên logic đã xây từ các tầng trước, tuyên ngôn tiêu chuẩn có thể được xác lập như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b8fe31b-7ce3-442d-91b9-a88b929ae9d2','1cad3c50-3751-4733-aa6c-7342fa29b913',203,'text','**“Chúng tôi là hệ thống nha khoa vận hành bằng tiêu chuẩn hóa và minh bạch. Chúng tôi ở đây để bình dân hóa kiến thức y khoa, giải quyết tận gốc nỗi sợ răng miệng của khách hàng và đồng hành cùng họ bằng khí chất chính trực của người thầy thuốc.”**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35cca658-c32d-4be2-bcb7-5a19a90ccebd','1cad3c50-3751-4733-aa6c-7342fa29b913',204,'text','Câu tuyên ngôn này có cấu trúc tương đối đầy đủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d5f7afc9-9a4c-428d-bde5-57240c832f29','1cad3c50-3751-4733-aa6c-7342fa29b913',205,'text','- Vế thứ nhất xác lập **danh tính vận hành**: đây là một hệ thống nha khoa, không phải một mô hình tự phát; và hệ thống ấy vận hành bằng tiêu chuẩn hóa cùng tính minh bạch của mã lệnh quản trị.- Vế thứ hai xác lập **mục đích phục vụ**: bình dân hóa kiến thức y khoa và giải quyết tận gốc nỗi sợ răng miệng  tức không chỉ điều trị bệnh, mà còn chữa cả sự thiếu hiểu biết và sự bất an vốn khiến bệnh nhân trì hoãn chăm sóc.- Phần cuối xác lập **khí chất tổ chức**: không chỉ đồng hành, mà đồng hành bằng khí chất chính trực của người thầy thuốc. Đây là lớp khóa lại phần Tenacity và đạo đức hành nghề.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ae4bac5-03e0-4ff8-9d07-83d3a6814085','1cad3c50-3751-4733-aa6c-7342fa29b913',206,'text','Với độ dài khoảng mười giây khi đọc thành tiếng, câu này đủ ngắn để sử dụng trong môi trường đào tạo và đủ chuẩn để lặp lại trên các nền tảng truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5902e357-15eb-4104-8c50-557471c47fb9','1cad3c50-3751-4733-aa6c-7342fa29b913',207,'text','Standardized Statement chỉ có giá trị khi được dùng như một chuẩn sống, chứ không phải một câu để treo cho đẹp. Vì vậy, tầng này cần được ứng dụng nhất quán ở ít nhất ba điểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1fedf194-8815-43f4-bfd3-7d58ae889303','1cad3c50-3751-4733-aa6c-7342fa29b913',208,'text','- **Trong onboarding nhân sự mới**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0954a269-4fd3-468f-8db0-a9453638754f','1cad3c50-3751-4733-aa6c-7342fa29b913',209,'text','Ngày đầu tiên của nhân sự mới không nên bắt đầu bằng checklist thủ tục, mà nên bắt đầu bằng định vị: “anh/chị đang bước vào một hệ thống như thế nào?”. Standardized Statement chính là câu mở đầu cho định vị đó. Nó giúp nhân sự mới hiểu rất nhanh rằng đây không chỉ là nơi làm việc, mà là một môi trường có danh tính rõ, có chuẩn vận hành rõ và có khí chất nghề nghiệp rõ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('833ab7d8-ff93-4c86-bd3a-37c3d4bcc984','1cad3c50-3751-4733-aa6c-7342fa29b913',210,'text','- **Trong sổ tay và tài liệu nội bộ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5a23f98-675a-49f9-b994-eb3e0bbaa4ee','1cad3c50-3751-4733-aa6c-7342fa29b913',211,'text','Tuyên ngôn tiêu chuẩn nên được đặt ở những vị trí mở đầu: trang đầu sổ tay nhân viên, handbook văn hóa, tài liệu orientation, module đào tạo quản lý và cả các tài liệu nền tảng của hệ điều hành. Khi được lặp lại đúng chỗ, câu tuyên ngôn này sẽ làm nhiệm vụ như một “chốt danh tính”, giúp mọi người không quên mình đang thuộc về hệ nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70f42091-6d28-464b-aa3e-0b55b268141c','1cad3c50-3751-4733-aa6c-7342fa29b913',212,'text','- **Trong truyền thông đối ngoại**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('157e1781-1dd5-4867-b64e-8e52ab88c865','1cad3c50-3751-4733-aa6c-7342fa29b913',213,'text','Mọi nội dung truyền thông trên website, TikTok, Facebook, YouTube hay các tài sản thương hiệu khác đều nên được kiểm tra ngược lại bằng Standardized Statement. Nếu nội dung nào khiến thương hiệu trở nên mập mờ, giật gân, thiếu minh bạch hoặc mất khí chất chính trực, nội dung đó đang đi lệch khỏi tuyên ngôn tiêu chuẩn. Khi dùng đúng, câu tuyên ngôn này sẽ giúp toàn bộ hoạt động truyền thông giữ được cùng một giọng nói gốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e488a76a-c98b-47df-94b9-52c0fed228ac','1cad3c50-3751-4733-aa6c-7342fa29b913',214,'text','**Mantra hành động**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a54acfeb-62c4-4019-a3f6-99e4f80b535c','1cad3c50-3751-4733-aa6c-7342fa29b913',215,'text','Nếu Standardized Statement là tuyên ngôn danh tính, thì **Mantra** là khẩu quyết tinh thần. Nó không thay thế tuyên ngôn, mà làm nhiệm vụ ngắn hơn, giàu nhịp hơn và dễ gọi dậy năng lượng hành động trong đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b11d6bf1-0139-49e0-a5bb-82b4cfa402e2','1cad3c50-3751-4733-aa6c-7342fa29b913',216,'text','Standardized Statement là tầng nén toàn bộ phần hồn của Layer 1 thành một câu danh tính có thể lặp lại, dùng được và sống được. Nó giúp hệ thống không chỉ có nền triết lý, mà còn có một biểu thức ngôn ngữ chuẩn để truyền thừa bản sắc cho nhân sự mới, khóa chuẩn cho tài liệu nội bộ và giữ trục nhất quán cho mọi hoạt động truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be1f6daa-9cb7-4dd2-8ba2-736e7aa5f125','1cad3c50-3751-4733-aa6c-7342fa29b913',217,'text','Nếu **Radicle** là rễ cọc, **Operating Code** là mã vận hành, **Outreach** là biên độ cắm rễ cho tương lai, và **Tenacity** là khí chất của đội ngũ, thì **Standardized Statement** chính là câu nói đóng dấu toàn bộ danh tính ấy. Nhờ đó, tổ chức không chỉ biết mình là ai trong tư duy, mà còn có thể nói rõ mình là ai bằng một ngôn ngữ ngắn gọn, chính xác và không thể bị pha loãng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6cf9ace3-d90f-4753-aae2-1afcb92adb6c','03-roadmap-to-be-sky-test',NULL,2,'3.3 LAYER 2: O - ONE LIGHT','33-layer-2-o-one-light',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13eda830-9189-4f9a-bdf9-ecba7e4d626a','6cf9ace3-d90f-4753-aae2-1afcb92adb6c',218,'text','Nếu **ROOTS** là nơi tổ chức xác định gốc rễ, gọi tên bản sắc và lựa chọn lý do tồn tại của mình, thì ONE LIGHT là tầng tâm gỗ và ánh sáng của tổ chức. ONE là phần lõi bất biến: Một lòng, Cao quý, Đạo đức. LIGHT là phần giá trị soi đường có thể được cá nhân hóa theo bản sắc riêng. Cây có thể cần những ánh sáng khác nhau, nhưng tâm gỗ bên trong thì phải giống nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85a8a2ce-606a-4102-888a-2c761c9748b6','6cf9ace3-d90f-4753-aae2-1afcb92adb6c',219,'text','Thân gỗ sẽ định hình cây sẽ lớn lên như thế nào, cành lá ra sao theo nguồn ánh sáng mà con chọn hướng đến. Không phải mọi cái cây đều cần cùng một lượng nắng. Có cây hợp ánh sáng gắt, có cây lớn lên trong vùng sáng dịu, có cây cần nhiều giờ mặt trời, có cây chỉ sống được dưới tán rừng. Nhưng dù hấp thụ ánh sáng theo cách nào, phần tâm gỗ bên trong vẫn phải chắc. Tổ chức cũng vậy. LIGHT có thể khác nhau, nhưng ONE phải giống nhau. Bởi ánh sáng giúp cây lớn lên, còn tâm gỗ mới quyết định cây có đứng vững hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8da3bc58-af44-4ae1-83e3-d06ec0fe31ca','03-roadmap-to-be-sky-test','6cf9ace3-d90f-4753-aae2-1afcb92adb6c',3,'ONE','one',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f79371c-f85b-4eca-b0e3-86527ea32e31','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',220,'text','**Tâm gỗ của tổ chức: phần lõi mà một doanh nghiệp muốn đi đường dài nào cũng nên có.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee2d9f8e-e4ca-49df-819a-ef15ded0f883','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',221,'text','Điểm chung của những cây cổ thụ không nằm ở việc chúng thuộc loài nào, sống ở vùng đất nào hay hấp thụ ánh sáng theo cách nào. Điểm chung của chúng là đều có một thân gỗ lớn, thẳng, bền, tán vươn rộng, rễ cắm sâu và một thời gian sinh trưởng đủ dài để tích lũy nội lực. Một tổ chức cũng vậy. Khi đã chọn trở thành một doanh nghiệp lâu năm, không chỉ **ROOTS** phải đủ sâu và đủ rộng, mà bên trên phần rễ ấy còn phải hình thành một “thân gỗ” đủ chắc để chống đỡ toàn bộ quá trình phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e6872a2-812e-457d-90ad-48e831aa8fd9','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',222,'text','Phần thân gỗ đó chính là **ONE**. Nếu ROOTS là nơi xác lập gốc rễ và bản sắc, thì ONE là lõi đứng thẳng ở bên trong tổ chức, là phần giúp doanh nghiệp không bị cong vênh trước áp lực, không bị mục ruỗng vì lợi ích ngắn hạn, và không đánh mất phẩm chất khi lớn lên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa19cad0-7bb3-4334-b0e6-a22a3206533d','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',223,'text','ONE cũng mang một tầng nghĩa rất đẹp: đó là **số một**, là **một**, là **duy nhất**. Nhưng ở đây, “một” không chỉ là đứng đầu, mà trước hết là **một lòng**, **một trục**, **một chuẩn giá trị không chia cắt**. Tổ chức chỉ có thể lớn bền khi bên trong nó có một lõi đủ thống nhất để mọi người cùng dựa vào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2921a69-09d0-4806-834d-9b5c8ebb63ef','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',224,'text','Vì thế, ONE được cấu thành bởi ba phẩm chất nền tảng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c6d24e0-b5be-4e3c-b91d-f1798ae117f2','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',225,'text','- **O - Oneness**: Một lòng, hợp nhất, đồng tâm trong tổ chức.- **N - Nobility**: Cao quý, giữ phẩm chất cao trong cách sống và cách làm việc.- **E - Ethics**: Đạo đức, lằn ranh đỏ không được vượt qua.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('63f958f1-1760-41f3-9aee-6b9d5eeb3fa6','8da3bc58-af44-4ae1-83e3-d06ec0fe31ca',226,'text','Nói ngắn gọn, nếu một tổ chức muốn trở thành cây lớn, thì ROOTS phải làm nhiệm vụ cắm sâu xuống đất, còn ONE phải làm nhiệm vụ trở thành thân gỗ. Rễ giúp cây sống được; nhưng chính thân gỗ mới giúp cây đứng thẳng, lớn cao và đi qua năm tháng mà không đánh mất hình hài của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('051f9ee3-39e9-4729-be07-02d6a879a131','03-roadmap-to-be-sky-test','6cf9ace3-d90f-4753-aae2-1afcb92adb6c',3,'LIGHTS','lights',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aad882eb-8d51-46f6-b558-7292f268a458','051f9ee3-39e9-4729-be07-02d6a879a131',227,'text','**Ánh sáng riêng của tổ chức**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e359e51-aa4f-4357-b0b2-b85e3468fe6e','051f9ee3-39e9-4729-be07-02d6a879a131',228,'text','Nếu ONE là phần tâm gỗ giữ cho cây đứng thẳng trước mưa gió, thì LIGHT là phần ánh sáng lặng lẽ nuôi cây lớn lên mỗi ngày. Không phải mọi cái cây đều cần cùng một lượng nắng, cũng như không phải mọi tổ chức đều phải mang cùng một bộ giá trị soi đường. Nhưng dù hấp thụ ánh sáng theo cách nào, phần lõi bên trong vẫn phải chắc. Bởi ánh sáng quyết định cách cây phát triển, còn tâm gỗ quyết định liệu cây có thể đứng vững suốt nhiều năm hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53f16a3c-5a69-4f40-9f70-13df58a4e46b','051f9ee3-39e9-4729-be07-02d6a879a131',229,'text','Trong tổ chức, LIGHT là phần ánh sáng soi đường cho sự trưởng thành. Nó là bộ giá trị mà doanh nghiệp lựa chọn để nuôi lớn bản sắc của mình qua từng quyết định, từng hành vi và từng giai đoạn phát triển. Nếu ONE là phần lõi giữ cho tổ chức đứng thẳng từ bên trong, thì LIGHT là phần dẫn sáng để tổ chức biết mình nên lớn lên theo hướng nào, với khí chất nào và bằng những phẩm chất nào',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('726f3639-5da6-44e9-a500-c24b850d7568','051f9ee3-39e9-4729-be07-02d6a879a131',230,'text','**Gợi ý các bộ LIGHT mà doanh nghiệp có thể chọn:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1a1610b5-117a-491d-8908-4fc5bf78e558','03-roadmap-to-be-sky-test','6cf9ace3-d90f-4753-aae2-1afcb92adb6c',3,'Tầm quan trọng của việc cá nhân hóa bộ nguyên tắc đạo đức','tam-quan-trong-cua-viec-ca-nhan-hoa-bo-nguyen-tac-ao-uc',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('43f3f3eb-17aa-4d22-8195-7bb2caf46659','1a1610b5-117a-491d-8908-4fc5bf78e558',231,'text','Mỗi doanh nghiệp là một thực thể duy nhất với văn hóa và sứ mệnh riêng. Do đó, bộ nguyên tắc đạo đức không nên là bản sao cứng nhắc từ xã hội, mà phải được cá nhân hóa dựa trên những giá trị đạo đức nền tảng đã được cộng đồng công nhận. Việc thiết lập các quy tắc tự điều chỉnh này giúp tổ chức bảo vệ tính liêm chính và tạo dựng niềm tin vững chắc với các bên liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53a2a4bd-3d0a-41a3-9180-dcbbeceea00c','1a1610b5-117a-491d-8908-4fc5bf78e558',232,'text','Để đạo đức không dừng lại ở những khẩu hiệu trừu tượng, mỗi nguyên tắc cần được cụ thể hóa bằng danh mục các hành vi **"Nên làm"** và **"Không được làm".**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd2378a6-65f5-4836-ac8f-b6671fdb9d5d','1a1610b5-117a-491d-8908-4fc5bf78e558',233,'text','- **Tính rõ ràng:** Đây là yếu tố then chốt để nhân viên ở mọi cấp bậc có thể nắm bắt và thực thi chính xác.- **Giảm thiểu rủi ro:** Sự tường minh trong các quy định giúp loại bỏ những "vùng xám" về đạo đức, từ đó ngăn ngừa các hành vi trục lợi hoặc vi phạm vô ý có thể gây tổn hại đến uy tín doanh nghiệp',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce100fb2-9407-493b-a6aa-462b65f0f90a','1a1610b5-117a-491d-8908-4fc5bf78e558',234,'text','Hệ thống đạo đức chỉ thực sự sống động khi nó được thẩm thấu vào tư duy của từng nhân sự thông qua các chương trình đào tạo nội bộ bài bản:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c42db63-366e-44ca-a4b1-aac57183fb28','1a1610b5-117a-491d-8908-4fc5bf78e558',235,'text','- **Nhân sự mới:** Cần được trang bị bộ quy tắc ngay từ ngày đầu gia nhập để đảm bảo sự hòa nhập về mặt văn hóa và chuẩn mực hành vi.- **Nhân sự cũ:** Cần được nhắc lại định kỳ để củng cố nhận thức và duy trì tính liêm chính trong môi trường làm việc lâu dài.- **Nâng cấp và thích ứng:** Khi môi trường kinh doanh thay đổi, các mô hình kinh doanh mới xuất hiện (ví dụ: sự can thiệp của AI hoặc làm việc từ xa), bộ nguyên tắc cũng cần được cập nhật để phản ánh đúng các thách thức đạo đức mới phát sinh',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bb28bfa-42ec-484d-ad5f-08d951940184','1a1610b5-117a-491d-8908-4fc5bf78e558',236,'text','Một sai lầm phổ biến trong quản trị là thiết lập chính sách trước khi xác lập nguyên tắc. Trong mô hình quản trị bền vững, **Nguyên tắc phải có trước Chính sách**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1496f44-b989-4fd5-a1ec-678e65cb36e1','1a1610b5-117a-491d-8908-4fc5bf78e558',237,'text','Các giá trị đạo đức đóng vai trò là "bộ lọc" cho chiến lược và quy trình vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9e96fe5-d9dc-47b8-8e75-b0f288c15f66','1a1610b5-117a-491d-8908-4fc5bf78e558',238,'text','Khi các nguyên tắc đã vững chắc, các chính sách được ban hành sau đó sẽ có tính nhất quán cao, dễ dàng được đội ngũ chấp nhận và thực thi một cách tự nguyện thay vì cưỡng ép.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01bc3fac-d1a3-45af-b0c6-b2d8950bf25e','1a1610b5-117a-491d-8908-4fc5bf78e558',239,'text','**Lời kết:**
Việc đầu tư xây dựng một Bộ Nguyên tắc Đạo đức (ONE LIGTH) không chỉ là tuân thủ pháp luật, mà là việc xây dựng một "di sản văn hóa" giúp tổ chức đứng vững trước mọi biến động của thị trường. Hãy để đạo đức trở thành ngôn ngữ chung của tất cả thành viên trong tổ chức của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fbff143-62e6-4c35-b6cb-cda33d21e9a1','1a1610b5-117a-491d-8908-4fc5bf78e558',240,'text','**Một lòng, cao quý, đạo đức; sống theo những giá trị soi đường.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e','03-roadmap-to-be-sky-test',NULL,2,'3.4 LAYER 3: A - AWAKEN','34-layer-3-a-awaken',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7803aa5-0682-4b4a-a8f2-778b39d4a5b4','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',241,'text','AWAKEN là tầng giúp hệ thống bắt đầu thức giấc trước thực tại. Đây không chỉ là một công cụ phát hiện vấn đề, mà là một giai đoạn phát triển của một hệ thống sống: khi nó không còn chỉ lớn lên theo quán tính, mà bắt đầu có khả năng cảm nhận môi trường, hiểu tín hiệu phản hồi và tự điều chỉnh để thích nghi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('28bd9215-adb2-4171-b75b-c42ee3c24822','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',242,'text','Ở tầng sinh học, một cái cây không phát triển bền vững nếu tách rời môi trường. Nó phải biết khi nào đất khô, khi nào thiếu sáng, khi nào gió đổi hướng, khi nào thân cần dày lên để chống chọi tốt hơn. Ở tầng con người, AWAKEN là quá trình tỉnh thức để hiểu mình, hiểu người và hiểu hoàn cảnh, từ đó sống hài hòa hơn với xã hội. Ở tầng tổ chức, AWAKEN là lúc doanh nghiệp bắt đầu nhìn rõ mình là ai, thị trường mình đang ở đâu, và những gì đang tác động lên mình để xây dựng một cơ chế phản ứng phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('706bae12-36d6-44ac-91ec-1c3e9d00686a','03-roadmap-to-be-sky-test','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',3,'AWAKEN là gì?','awaken-la-gi',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b52be38-60de-493e-b516-158d32c716a5','706bae12-36d6-44ac-91ec-1c3e9d00686a',243,'text','**AWAKEN** là framework nhận diện sớm trong **R.O.A.D.M.A.P**. Nó giúp tổ chức kiểm tra thực trạng, quan sát thị trường, vẽ bản đồ khoảng cách, hiểu vị trí thật, đào sâu nguyên nhân và nhận ra tín hiệu sớm trước khi ra quyết định chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9092cb2f-6422-435a-8b78-8c41fedcaaf8','706bae12-36d6-44ac-91ec-1c3e9d00686a',244,'text','Nói ngắn gọn, AWAKEN là quá trình **thức giấc của một hệ thống sống**: cây thức giấc khi biết lắng nghe môi trường để thích nghi; con người "thức giấc" khi bắt đầu hiểu mình và hiểu xung quanh để sống hài hòa; tổ chức "thức giấc" khi biết nhìn đúng thực trạng để phản ứng có ý thức thay vì phản ứng theo bản năng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a3e90aa7-33f3-47d4-bc22-2560fb0158d8','03-roadmap-to-be-sky-test','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',3,'Vì sao cần AWAKEN?','vi-sao-can-awaken',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9eefc542-93ae-4b19-9dd0-72bf0c957d0b','a3e90aa7-33f3-47d4-bc22-2560fb0158d8',245,'text','Một tổ chức chỉ có thể cải tiến đúng khi nhìn đúng thực trạng. Nếu không có tầng nhận diện này, doanh nghiệp rất dễ rơi vào phản xạ chữa bề mặt: thấy doanh thu giảm thì ép sale, thấy khách hàng phàn nàn thì sửa lời thoại, thấy nhân sự yếu thì thay người, thấy vận hành chậm thì thêm checklist. Những phản ứng đó đôi khi cần thiết, nhưng nếu không đi qua bước nhìn sâu, hệ thống sẽ chỉ chữa triệu chứng mà bỏ quên căn nguyên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c15be54-7ec1-4e2c-b7c6-b0c74aae4c8a','a3e90aa7-33f3-47d4-bc22-2560fb0158d8',246,'text','AWAKEN tồn tại để ngăn điều đó. Nó giúp tổ chức không xử lý phần ngọn trong khi phần gốc vẫn âm thầm mục ruỗng. Trong môi trường nha khoa, điều này càng quan trọng vì sai lệch vận hành thường không bộc lộ ngay thành khủng hoảng lớn; chúng thường xuất hiện trước như những tín hiệu nhỏ, rời rạc và dễ bị xem nhẹ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2e968472-24d0-4d2d-8d75-9811c041c2d8','03-roadmap-to-be-sky-test','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',3,'Ba lớp "thức giấc"','ba-lop-thuc-giac',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21b75329-52bf-4944-a6d1-e75153037a05','2e968472-24d0-4d2d-8d75-9811c041c2d8',247,'text','Một cái cây không thể sống lâu chỉ bằng việc vươn lên. Nó phải học cách tiếp nhận phản hồi từ môi trường và điều chỉnh cách sinh trưởng của mình. Khi đất thay đổi, cây đổi cách bám rễ. Khi ánh sáng thay đổi, cây đổi hướng phát triển. Khi gió mạnh lên, cây làm thân mình vững hơn. Sự sống của cây là một quá trình vừa tiếp nhận vừa thích nghi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('43a4a23a-470c-466a-89b6-1e7b6f5168aa','2e968472-24d0-4d2d-8d75-9811c041c2d8',248,'text','Vì thế, AWAKEN trước hết là sự thức giấc của một sinh thể sống trước môi trường. Nó không còn lớn một cách mù quáng, mà bắt đầu xây dựng cơ chế phản ứng với thế giới xung quanh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3fb89c33-b57f-459f-bcc0-00213236117f','2e968472-24d0-4d2d-8d75-9811c041c2d8',249,'text','Với con người, AWAKEN là quá trình dần tỉnh thức. Một người chưa AWAKEN thường sống bằng phản ứng nhanh hơn là hiểu sâu. Họ dễ bị cuốn theo cảm xúc, va chạm với người khác, và hành xử nhiều khi không ý thức được mình đang tác động lên môi trường sống chung như thế nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('773d1f9a-4aa0-4f93-ba28-33d802cf9f5d','2e968472-24d0-4d2d-8d75-9811c041c2d8',250,'text','Khi AWAKEN bắt đầu diễn ra, con người học được cách quan sát chính mình, nhận ra giới hạn của mình, hiểu cảm xúc và động cơ của mình, đồng thời biết nhìn ra thế giới bên ngoài với sự bình tĩnh hơn. Từ đó, họ không chỉ sống để tồn tại, mà sống để hòa hợp. Họ hiểu mình, hiểu người, và nhờ đó sống cùng xã hội một cách trưởng thành hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86d2e610-ac83-4590-986b-33eec3e74df6','2e968472-24d0-4d2d-8d75-9811c041c2d8',251,'text','Với tổ chức, AWAKEN là giai đoạn hệ thống bắt đầu nhìn ra bản thân một cách trung thực. Doanh nghiệp cần biết mình là ai, mình đang ở đâu, thị trường mình là gì, những gì đang tác động lên mình, và đâu là những lực đẩy hoặc lực kéo đang ảnh hưởng đến tương lai của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c29f3a7d-7ef9-4e9f-8bd7-0ee72ae0930f','2e968472-24d0-4d2d-8d75-9811c041c2d8',252,'text','Một tổ chức chưa AWAKEN thường vận hành trong trạng thái mù một phần: làm việc rất chăm nhưng không biết điều gì đang thật sự kéo mình lệch khỏi mục tiêu. Khi AWAKEN xuất hiện, tổ chức có thể xây dựng cơ chế quan sát, cơ chế kiểm tra, cơ chế phân tích, cơ chế điều chỉnh và cơ chế học từ sai lệch. Đó là lúc hệ thống bắt đầu phản ứng có ý thức, thay vì phản ứng theo bản năng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('26dba88b-6cdb-44f0-aa27-a7492fb5b6bf','03-roadmap-to-be-sky-test','fea4e026-fe3f-43a4-9ac9-b28a8e4fa81e',3,'Cấu trúc AWAKEN','cau-truc-awaken',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a7154da-3f87-420e-854a-bf99efd594ca','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',253,'text','- **Audit** là kiểm tra nội bộ toàn hệ thống. - Tổ chức nhìn lại thương hiệu, vận hành, nhân sự, dữ liệu, quy trình, chất lượng dịch vụ và trải nghiệm khách hàng để biết thực trạng thật đang là gì.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89e2299a-0795-43b8-80a4-b6295a2b0b9f','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',254,'text','- **Watch** là quan sát thế giới bên ngoài. - Tổ chức phải nhìn thị trường, đối thủ, khách hàng và xu hướng để hiểu môi trường xung quanh đang thay đổi thế nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('450b7417-eef3-4b72-bffa-dd640203c911','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',255,'text','- **Map** là vẽ bản đồ hiện trạng. - Đây là bước ghép dữ liệu thành bức tranh có cấu trúc: mình đang ở đâu, mục tiêu ở đâu, khoảng cách ở đâu, và điểm nghẽn nằm ở đâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba3aaa51-d4fb-4ccf-9581-6588f9826386','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',256,'text','- **Know** là biết rõ tình trạng thật của doanh nghiệp. - Không chỉ biết chung chung, mà là biết mình mạnh ở đâu, yếu ở đâu, đang thiếu gì và còn lệch gì so với mục tiêu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('986208d7-e7ea-4d45-b88c-9b38530e0cc8','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',257,'text','- **Examine** là đào sâu đánh giá nguyên nhân gốc. - Tổ chức không dừng ở việc thấy vấn đề, mà phải đi tới cơ chế tạo ra vấn đề, rồi đi tiếp xuống những niềm tin và giả định đang chi phối cơ chế đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd23b16a-05bb-4f7e-8769-96e7e52b1ffc','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',258,'text','- **Notice** là nhận ra tín hiệu sớm, nhỏ nhưng quan trọng thông báo để phản ứng. - Một vài ca khiếu nại lặp lại, sự chậm trễ kéo dài, sự im lặng bất thường của đội ngũ hay dữ liệu lệch nhẹ nhưng liên tục đều có thể là dấu hiệu của một vấn đề lớn hơn đang hình thành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62cea2f4-5cb5-4c70-b132-bdafefbf0536','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',259,'text','Trong môi trường nha khoa, AWAKEN rất quan trọng vì sai lệch vận hành thường không xuất hiện ngay dưới dạng khủng hoảng lớn, mà khởi đầu từ những tín hiệu nhỏ: lịch hẹn trễ dần, phản hồi khách hàng lặp lại, tư vấn lệch chuẩn, dữ liệu không đồng nhất, hoặc cảm giác mọi thứ vẫn chạy nhưng không còn mượt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed03a49b-f715-4cfc-915f-001b5b59b4ec','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',260,'text','Khi AWAKEN được triển khai đúng, phòng khám sẽ không còn chỉ phản ứng sau khi sự cố xảy ra. Tổ chức sẽ có năng lực kiểm tra định kỳ, quan sát thị trường, vẽ lại bản đồ khoảng cách, xác nhận vị trí thật, đào sâu nguyên nhân và phát hiện tín hiệu sớm để can thiệp trước khi vấn đề lớn lên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f151aff7-5a57-4105-81d9-633ff42891e9','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',261,'text','Điều này đặc biệt quan trọng với phòng khám đang muốn mở rộng quy mô. Một hệ thống chưa biết rõ mình đang ở đâu thì rất khó đi đúng hướng. AWAKEN giúp tổ chức tránh việc mở rộng trên một nền hiểu biết mơ hồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7990afa4-6463-4ca7-b8db-99fa1358e9a6','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',262,'text','AWAKEN là tầng đánh thức năng lực nhìn thật của tổ chức. Nó giúp doanh nghiệp không bị cuốn vào việc chữa triệu chứng, mà quay về tìm đúng căn nguyên. Khi một phòng khám biết kiểm tra nội bộ, quan sát bên ngoài, vẽ bản đồ hiện trạng, hiểu rõ mình đang ở đâu, đào sâu nguyên nhân và nhận ra tín hiệu sớm, lúc đó tổ chức mới thật sự có năng lực tự sửa mình trước khi thị trường buộc phải sửa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db97b626-cccf-49cd-b238-55a13ec21ded','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',263,'text','**Kiểm tra → Quan sát → Vẽ bản đồ → Hiểu rõ → Đào sâu → Nhận diện tín hiệu sớm.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b288b95e-9eeb-4fbf-bbc5-0cd21c0e4aab','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',264,'text','**Audit the system, Watch the environment, Map the gap, Know the reality, Examine the root cause, Notice the early signals.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('393aa530-7e28-40c5-96fd-98a6f78006fb','26dba88b-6cdb-44f0-aa27-a7492fb5b6bf',265,'text','**Audit → Watch → Map → Know → Examine → Notice.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b41551d-68ad-4be2-96ff-352d0362b155','03-roadmap-to-be-sky-test',NULL,2,'3.5 LAYER 4: D - DEEPEN','35-layer-4-d-deepen',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ac5f634-9691-4dd8-8c24-b0297ceca2a2','8b41551d-68ad-4be2-96ff-352d0362b155',266,'text','Nếu những tầng trước giúp tổ chức nhận diện đúng, giữ đúng và định hướng đúng, thì **DEEPEN** là tầng giúp hệ thống đưa cái đúng đó đi vào chiều sâu của vận hành. Đây là bước mà một năng lực, một quy trình hay một tiêu chuẩn không còn dừng ở mức “biết là nên làm”, mà bắt đầu được đào sâu, chuẩn hóa và biến thành nếp sống của toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cbfc5e6-1174-49dc-bf69-10173dbce74e','8b41551d-68ad-4be2-96ff-352d0362b155',267,'text','Trong một tổ chức phát triển bền vững, điều quan trọng không chỉ là có ý tưởng tốt hay nguyên tắc đúng. Quan trọng hơn là tổ chức có đủ năng lực để bóc tách nó thành cấu trúc rõ ràng, đóng gói thành quy trình, ép vào thực thi và lặp lại đủ lâu để nó trở thành bình thường mới. Đó chính là vai trò của DEEPEN.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a1660f83-5364-44f9-90ac-f37869ee2bea','03-roadmap-to-be-sky-test','8b41551d-68ad-4be2-96ff-352d0362b155',3,'DEEPEN là gì?','deepen-la-gi',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed4f76f5-1543-4688-832b-fb3f455bb758','a1660f83-5364-44f9-90ac-f37869ee2bea',268,'text','**DEEPEN** là framework đào sâu và chuẩn hóa năng lực trong tổ chức. Nó giúp doanh nghiệp xác định đúng thứ cần làm sâu, nâng chất lượng của nó lên, làm rõ từng chi tiết, chuyển hóa thành quy trình chuẩn, bảo đảm thực thi và cuối cùng biến nó thành nếp vận hành của hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a79e3a34-bd07-47b0-b5e9-454031a72e64','a1660f83-5364-44f9-90ac-f37869ee2bea',269,'text','Nói ngắn gọn, DEEPEN là quá trình **đào sâu năng lực, chuẩn hóa SOP và biến chuẩn mực thành nếp vận hành**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8eb02d5a-199e-45b5-bb53-b0fd649e4fa3','03-roadmap-to-be-sky-test','8b41551d-68ad-4be2-96ff-352d0362b155',3,'Vì sao cần DEEPEN?','vi-sao-can-deepen',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a0d7884-61c0-43b0-86cb-e39b5375db41','8eb02d5a-199e-45b5-bb53-b0fd649e4fa3',270,'text','Một tổ chức có thể biết điều gì là đúng, nhưng vẫn không thực hiện được đúng nếu không có tầng chuyển hóa. Nhiều hệ thống thất bại không phải vì thiếu nguyên tắc, mà vì nguyên tắc không được đi đến mức đủ sâu để trở thành quy trình, trách nhiệm, checklist và kỷ luật vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e4e0919-ad0a-4b52-9770-0245a92b4ae1','8eb02d5a-199e-45b5-bb53-b0fd649e4fa3',271,'text','DEEPEN tồn tại để lấp đầy khoảng trống đó. Nó giúp tổ chức không chỉ nói về tiêu chuẩn, mà còn biến tiêu chuẩn thành cấu trúc sống được trong thực tế. Đó là bước từ tư duy sang thực thi, từ ý tưởng sang hệ thống, từ cái đúng trong đầu người lãnh đạo sang cái đúng có thể lặp lại trong đời sống tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1544aec4-401a-4418-9ba1-70c9774fd751','03-roadmap-to-be-sky-test','8b41551d-68ad-4be2-96ff-352d0362b155',3,'Cấu trúc DEEPEN','cau-truc-deepen',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('846d4ffa-862c-49d1-99de-44d3b82e731f','1544aec4-401a-4418-9ba1-70c9774fd751',272,'text','**Define** là bước xác định rõ điều gì cần được đào sâu. Tổ chức phải nói rõ mình đang cần chuẩn hóa năng lực nào, quy trình nào, vấn đề nào hoặc hành vi nào. Nếu không định nghĩa rõ, mọi nỗ lực cải tiến sẽ rất dễ lan man và thiếu trọng tâm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb2099fe-1047-4ec3-8248-351b9155eeea','1544aec4-401a-4418-9ba1-70c9774fd751',273,'text','Define giúp hệ thống trả lời câu hỏi: ta đang cần làm sâu cái gì, và vì sao nó quan trọng đến mức phải chuẩn hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b5baf3ed-efa4-4bbd-85a8-838d1e374159','1544aec4-401a-4418-9ba1-70c9774fd751',274,'text','**Enhance** là nâng chất lượng của năng lực hoặc cách làm lên mức tốt hơn. Không phải cái gì cũng cần tạo mới hoàn toàn; nhiều khi vấn đề là cái đang có chưa đủ mạnh, chưa đủ tốt, chưa đủ ổn định để trở thành nền tảng dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc218a74-3008-460b-b54a-86aef8190512','1544aec4-401a-4418-9ba1-70c9774fd751',275,'text','Enhance là bước làm cho cái đúng trở nên tốt hơn, sắc hơn và mạnh hơn trước khi đưa nó vào hệ thống hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00a4a97b-e9cf-49ab-82a4-d517c8ffc0f9','1544aec4-401a-4418-9ba1-70c9774fd751',276,'text','**Elaborate** là làm rõ chi tiết. Ở bước này, tổ chức bóc tách từng bước, từng điều kiện, từng tiêu chuẩn, từng ngoại lệ và từng tình huống có thể xảy ra. Một tiêu chuẩn nếu chưa được làm rõ thì vẫn chỉ là khái niệm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('946e7471-c738-4cb9-8b7c-acaf3f61e1e0','1544aec4-401a-4418-9ba1-70c9774fd751',277,'text','Elaborate giúp biến điều mơ hồ thành điều có thể dạy, có thể theo dõi và có thể kiểm tra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a04c67d2-8393-4771-9e6c-80b322889848','1544aec4-401a-4418-9ba1-70c9774fd751',278,'text','**Process** là đóng gói thành quy trình chuẩn. Đây là lúc điều đã được làm rõ bắt đầu được chuyển thành SOP, quy trình lặp lại, tài liệu hướng dẫn và logic chuyển giao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('499930bb-9806-445b-9b89-f082afadf0d1','1544aec4-401a-4418-9ba1-70c9774fd751',279,'text','Process là bước cực kỳ quan trọng, vì nếu không có quy trình, tổ chức sẽ phụ thuộc quá nhiều vào cá nhân giỏi. Khi đó hệ thống không bền, vì người giỏi nghỉ đi thì chuẩn mực cũng dễ tan theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91be921f-8618-4a05-bd18-7b006869ef01','1544aec4-401a-4418-9ba1-70c9774fd751',280,'text','**Enforce** là bảo đảm thực thi. Một quy trình chỉ thật sự có giá trị khi nó được ép vào thực tế bằng checklist, KPI, trách nhiệm, quyền hạn và cơ chế kiểm soát.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ba90507-dd3f-4ade-86a7-f805bc890202','1544aec4-401a-4418-9ba1-70c9774fd751',281,'text','Enforce không có nghĩa là cứng nhắc vô cảm, mà là tổ chức phải có khả năng bảo vệ chuẩn bằng hành động cụ thể. Nếu không enforce, SOP sẽ chỉ nằm trên giấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2eb058e5-0f75-48a9-8fa9-87e686f9bee3','1544aec4-401a-4418-9ba1-70c9774fd751',282,'text','**Normalize** là biến chuẩn thành nếp vận hành bình thường của hệ thống. Đây là đích đến của toàn bộ quá trình DEEPEN. Khi một chuẩn đã được làm đủ rõ, đủ tốt, đủ lặp lại và đủ được thực thi, nó không còn là “việc đặc biệt nữa”, mà trở thành cách làm mặc định của toàn tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('18b87172-a6a9-478d-900d-4423c96f2290','1544aec4-401a-4418-9ba1-70c9774fd751',283,'text','Normalize là lúc chuẩn mực không cần phải nhắc quá nhiều vì nó đã đi vào thói quen, phản xạ và văn hóa làm việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d2accd8e-67d1-47ab-b44a-a507db093ec3','03-roadmap-to-be-sky-test','8b41551d-68ad-4be2-96ff-352d0362b155',3,'Ý nghĩa quản trị','y-nghia-quan-tri',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0501a392-01f5-4360-886a-0832445a877f','d2accd8e-67d1-47ab-b44a-a507db093ec3',284,'text','DEEPEN là tầng giúp hệ thống không chỉ hiểu đúng việc cần đào sâu mà còn chuyển nó thành SOP, trách nhiệm, KPI và kỷ luật vận hành. Đây là cầu nối giữa nhận thức và thực tế, giữa tiêu chuẩn và hành vi, giữa thiết kế và lặp lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b5179b3f-4941-4766-ad1b-5d911f4184e8','d2accd8e-67d1-47ab-b44a-a507db093ec3',285,'text','Trong một tổ chức nha khoa, điều này đặc biệt quan trọng vì chất lượng chuyên môn, trải nghiệm bệnh nhân, tính an toàn và độ tin cậy của hệ thống đều không thể dựa vào cảm hứng cá nhân. Chúng phải được đóng gói thành cách làm chung, được duy trì đủ lâu và được kiểm soát đủ chặt để không bị trượt chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5a66df4d-a092-4dad-94d7-a3eb370e4517','03-roadmap-to-be-sky-test','8b41551d-68ad-4be2-96ff-352d0362b155',3,'Kết luận:','ket-luan',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15e3474c-0e52-4458-810c-6fcc24eb71d1','5a66df4d-a092-4dad-94d7-a3eb370e4517',286,'text','DEEPEN là cách tổ chức biến năng lực thành chuẩn, biến chuẩn thành quy trình, và biến quy trình thành nếp vận hành. Khi một hệ thống đủ sâu để tự chuẩn hóa chính mình, nó không chỉ làm tốt hơn mà còn bền hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdbfb502-8fea-491a-8a0b-4c7256c29d4e','5a66df4d-a092-4dad-94d7-a3eb370e4517',287,'text','Đào sâu năng lực, chuẩn hóa SOP, và biến chuẩn mực thành nếp vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('399536ee-c038-40b1-8c0b-b1a81ea08ded','5a66df4d-a092-4dad-94d7-a3eb370e4517',288,'text','**Xác định → Nâng chất → Làm rõ → Đóng gói quy trình → Thực thi → Chuẩn hóa thành nếp.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02730e8b-4b52-4e41-ab40-e059f566096f','5a66df4d-a092-4dad-94d7-a3eb370e4517',289,'text','**Define the need, Enhance the quality, Elaborate the details, Process into SOP, Enforce execution, Normalize into habit**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e354722-ee32-4f36-a030-9a99d56819af','5a66df4d-a092-4dad-94d7-a3eb370e4517',290,'text','**Define → Enhance → Elaborate → Process → Enforce → Normalize.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b6b124a-39be-432b-93e5-fec020ec5178','03-roadmap-to-be-sky-test',NULL,2,'3.6 LAYER 6: M - MATURE','36-layer-6-m-mature',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1156da8-8269-40b8-8134-d82232b24f13','8b6b124a-39be-432b-93e5-fec020ec5178',291,'text','Nếu những tầng trước giúp tổ chức nhận diện đúng, chuẩn hóa đúng và đào sâu đúng, thì **MATURE** là tầng giúp toàn hệ thống bước vào trạng thái chín hơn. Đây không chỉ là giai đoạn tổ chức lớn lên về quy mô, mà là giai đoạn nó trưởng thành hơn về nhịp, rõ hơn về chuẩn, mạnh hơn về niềm tin và linh hoạt hơn trong khả năng tự nâng cấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa5abd0d-0982-4d5e-b6d4-ab59d618ffdb','8b6b124a-39be-432b-93e5-fec020ec5178',292,'text','Trong thực tế, rất nhiều tổ chức có thể tăng nhanh, nhưng không phải tổ chức nào cũng chín. Có những hệ thống đi rất nhanh nhưng vẫn rời rạc, thiếu đà, thiếu sự ăn khớp giữa con người và cơ chế, thiếu niềm tin nội bộ, và thiếu năng lực tự tinh chỉnh khi môi trường thay đổi. MATURE tồn tại để xử lý chính khoảng trống đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fcfa7954-1474-4f8f-a59c-81ecfd334ace','03-roadmap-to-be-sky-test','8b6b124a-39be-432b-93e5-fec020ec5178',3,'MATURE là gì?','mature-la-gi',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4358f4dc-82ba-4b06-b418-f60d693e4346','fcfa7954-1474-4f8f-a59c-81ecfd334ace',293,'text','**MATURE** là framework mô tả tiến trình làm cho hệ thống có đà phát triển, đồng bộ hơn, đáng tin cậy hơn, gắn kết hơn, tinh gọn hơn và có khả năng nâng cấp liên tục trong thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f20da85-626c-4e1d-82d8-3685bc33f5b4','fcfa7954-1474-4f8f-a59c-81ecfd334ace',294,'text','Nói ngắn gọn, **MATURE là quá trình tạo đà, chỉnh nhịp, xây niềm tin, hợp lực, tinh chỉnh và nâng tầng** để hệ thống phát triển bền hơn thay vì chỉ chạy nhanh hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c3f25cb3-193b-4979-bd17-191519424410','03-roadmap-to-be-sky-test','8b6b124a-39be-432b-93e5-fec020ec5178',3,'Vì sao cần MATURE?','vi-sao-can-mature',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b30dac3-ab2e-49bb-a095-aeb61af99fbc','c3f25cb3-193b-4979-bd17-191519424410',295,'text','Một tổ chức muốn đi đường dài không thể chỉ dựa vào động lực ban đầu. Động lực có thể giúp khởi động, nhưng không đủ để giữ cho hệ thống bền, đều và có khả năng tự điều chỉnh sau những lần va đập. Khi một doanh nghiệp chưa mature, nó thường biểu hiện bằng nhịp vận hành lệch nhau giữa các bộ phận, niềm tin nội bộ chưa đủ vững, quy trình còn nhiều ma sát và khả năng cải tiến chưa đủ ổn định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('024852bf-4ccf-4e75-9b9e-e3115fd1ae95','c3f25cb3-193b-4979-bd17-191519424410',296,'text','MATURE giúp hệ thống chuyển từ trạng thái “đang chạy” sang trạng thái “đang chín”. Đó là khác biệt giữa việc có hoạt động và việc thật sự có tiến hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c','03-roadmap-to-be-sky-test','8b6b124a-39be-432b-93e5-fec020ec5178',3,'Cấu trúc MATURE','cau-truc-mature',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b542955-77f2-4254-ac5d-714395cbe793','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',297,'text','**Momentum** là tạo đà phát triển để hệ thống không vận hành theo kiểu rời rạc hay thiếu lực kéo. Một tổ chức không có momentum thường phải bắt đầu lại quá nhiều lần, mất nhiều năng lượng cho việc khởi động mà không đủ độ trôi để tiến xa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fa6861b-88e9-453d-a349-1bac74ab83d2','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',298,'text','Momentum là nền của sự liên tục. Khi hệ thống có đà, mọi nỗ lực nhỏ sẽ cộng dồn tốt hơn, và tổ chức không còn phải kéo từng bước bằng ý chí cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21cc34c0-4794-4ca2-9dcc-ba24d6cdbf3b','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',299,'text','- **Attune** là chỉnh nhịp mục tiêu, con người và cơ chế để toàn hệ cùng tần số. Đây là bước làm cho chiến lược, vai trò và nhịp vận hành không đi lệch nhau.- Một hệ thống không attune sẽ dễ xảy ra tình trạng mục tiêu một đằng, con người một nẻo, cơ chế một kiểu. Attune giúp mọi phần của tổ chức cùng “nghe” được một bản nhạc chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e3b5e5f-6d60-467c-b6f8-79c82d6f2c09','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',300,'text','- **Trust** là xây niềm tin bằng tính nhất quán, tiêu chuẩn rõ và trải nghiệm thật trong vận hành. Niềm tin trong tổ chức không đến từ lời nói hay khẩu hiệu, mà từ việc hệ thống làm đúng đủ lâu để tạo ra cảm giác an tâm thật.- Trust làm cho con người tin vào nhau, tin vào quy trình và tin vào năng lực chung của tổ chức. Không có trust, mọi cơ chế đều phải kiểm soát quá mức và chi phí vận hành sẽ tăng lên rất nhiều.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b67c42d3-a389-4da6-91de-a39dc783bb50','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',301,'text','- **Unite** là gắn kết vai trò, bộ phận và nguồn lực thành một khối phối hợp hiệu quả. Một tổ chức Mature không cho phép các phần của mình hoạt động như những ốc đảo riêng lẻ.- Unite biến sự có mặt của nhiều bộ phận thành một sức mạnh hợp lực. Khi mọi phần cùng đi về một hướng, hệ thống không chỉ mạnh hơn mà còn ít hao tổn hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('284bbd0d-ac45-4342-b53f-0a2ac306cf95','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',302,'text','- **Refine** là tinh chỉnh quy trình, cấu trúc và cách làm để giảm ma sát và tăng độ sắc nét của hệ thống. Không phải cứ có quy trình là đủ; quy trình cần được mài lại cho gọn hơn, rõ hơn và dễ vận hành hơn.- Refine là bước giúp tổ chức bớt nặng nề, bớt rối và bớt lãng phí năng lượng vào những chỗ không cần thiết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('080c6d31-ccb2-4f5d-accf-d6068937b8c9','3b0e7cba-6fd1-4cec-a57b-b04e8c0ada5c',303,'text','- **Elevate** là nâng cấp chuẩn vận hành, năng lực đội ngũ và chất lượng tăng trưởng lên tầng cao hơn. Đây là đích đến của MATURE: không chỉ ổn định hơn, mà còn cao hơn về chuẩn, sâu hơn về năng lực và tốt hơn về chất lượng phát triển.- Elevate là lúc tổ chức không còn chỉ giữ mức tốt hiện tại, mà bắt đầu đi lên một nấc mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4f3e4090-9c55-49c5-a35b-c3cc339e67dd','03-roadmap-to-be-sky-test','8b6b124a-39be-432b-93e5-fec020ec5178',3,'Ý nghĩa trong mạch phát triển','y-nghia-trong-mach-phat-trien',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1aebd6db-10d7-4c64-abc0-bb6bc8a04588','4f3e4090-9c55-49c5-a35b-c3cc339e67dd',304,'text','Trong mạch phát triển hiện tại, MATURE diễn tả giai đoạn hệ thống không chỉ lớn hơn mà còn chín hơn về nhịp, rõ hơn về chuẩn, mạnh hơn về niềm tin và tốt hơn về khả năng tự nâng cấp. Nó là một tầng rất cần thiết nếu tổ chức muốn chuyển từ tăng trưởng ngắn hạn sang tăng trưởng có độ ổn định cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('638173f6-bfcb-45f1-b20e-8034e9a36a80','4f3e4090-9c55-49c5-a35b-c3cc339e67dd',305,'text','Ở đây, “mature” không chỉ là trưởng thành theo tuổi đời. Nó là trưởng thành theo cấu trúc: biết tạo đà, biết chỉnh nhịp, biết xây trust, biết hợp lực, biết tinh chỉnh và biết nâng tầng liên tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ef2f94fe-b368-4be2-b358-0b5d4a2f8875','03-roadmap-to-be-sky-test','8b6b124a-39be-432b-93e5-fec020ec5178',3,'Kết luận:','ket-luan',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('700e3a7c-d528-4f6a-a5fb-e8686c32fbf3','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',306,'text','MATURE là tầng cho thấy một hệ thống không chỉ cần lớn lên, mà còn cần **chín** lên. Nếu momentum giúp tổ chức có đà để đi, attune giúp mọi phần cùng chung nhịp, trust giúp hệ thống đáng tin cậy hơn, unite giúp nguồn lực được hợp lực, refine giúp cấu trúc trở nên sắc nét hơn, thì elevate là đích đến tự nhiên của toàn bộ quá trình ấy: một chuẩn cao hơn, một cách vận hành tốt hơn, và một năng lực tăng trưởng bền hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2348e39f-af2c-4d13-b273-537b77167574','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',307,'text','Nói cách khác, MATURE không đơn thuần là làm cho hệ thống chạy nhanh hơn. Nó làm cho hệ thống **đi xa hơn mà không vỡ nhịp**, **lớn hơn mà không rời rạc**, và **cao hơn mà không mất nền**. Đó là sự trưởng thành thật của một tổ chức: biết tạo đà, biết chỉnh nhịp, biết xây niềm tin, biết hợp lực, biết tinh chỉnh và biết liên tục nâng cấp chính mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff7f062f-5e09-481c-b96a-2a94920112da','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',308,'text','Khi một tổ chức đi qua MATURE, nó không còn chỉ là một cỗ máy đang hoạt động, mà trở thành một hệ thống sống có khả năng tự đồng bộ, tự nâng chuẩn và tự tiến hóa. Và chính khả năng đó mới là dấu hiệu rõ nhất của một tổ chức đã bước vào giai đoạn trưởng thành bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48dabfe1-a96e-482a-aaef-c4cf703f441a','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',309,'text','**Tạo đà → Chỉnh nhịp → Xây trust → Hợp lực → Tinh chỉnh → Nâng tầng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7dafa52-04cb-49cc-96d3-cd5192111191','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',310,'text','**Momentum → Attune → Trust → Unite → Refine → Elevate.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09b9bce1-b6eb-413c-99dc-3c449d64ce66','ef2f94fe-b368-4be2-b358-0b5d4a2f8875',311,'text','**Build momentum, attune the system, earn trust, unite the force, refine the process, elevate the standard.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('19cf738c-284a-4df0-afbd-312ecf2e0611','03-roadmap-to-be-sky-test',NULL,2,'3.7 LAYER 7: A - ALIGN','37-layer-7-a-align',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36a9fe59-6235-4800-8478-9bc732d780b4','19cf738c-284a-4df0-afbd-312ecf2e0611',312,'text','Nếu những tầng trước giúp tổ chức nhìn ra, chuẩn hóa và trưởng thành hơn, thì **ALIGN** là tầng giúp toàn bộ hệ thống đi vào trạng thái đồng bộ thật sự. Đây là bước mà mục tiêu, con người, nguồn lực, quy trình và cơ chế phối hợp không còn vận hành theo các nhịp riêng lẻ, mà bắt đầu được neo lại, nối lại, tích hợp lại và tinh chỉnh lại để đi cùng một hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3eb6ecb-722b-45ed-90cc-6d9b5bd6ec1f','19cf738c-284a-4df0-afbd-312ecf2e0611',313,'text','Trong thực tế, nhiều tổ chức không thất bại vì thiếu nỗ lực. Họ thất bại vì quá nhiều thứ cùng chạy nhưng không chạy cùng nhịp. Bộ phận này hiểu một kiểu, bộ phận khác hiểu một kiểu; kế hoạch có, nhưng nguồn lực không nối đúng; quy trình có, nhưng cơ chế quản trị chưa đủ chặt; mục tiêu có, nhưng khoảng lệch giữa kế hoạch và thực thi vẫn còn rất lớn. ALIGN sinh ra để xử lý chính sự lệch pha đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a1417300-6c24-4e67-a618-f39814b35dce','03-roadmap-to-be-sky-test','19cf738c-284a-4df0-afbd-312ecf2e0611',3,'ALIGN là gì?','align-la-gi',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29eacdbf-cca5-4df6-9246-7bf9c2e3066b','a1417300-6c24-4e67-a618-f39814b35dce',314,'text','**ALIGN** là framework đồng bộ hóa hệ thống trong R.O.A.D.M.A.P. Nó giúp tổ chức neo mục tiêu chung, kết nối con người và nguồn lực, tích hợp quy trình và vai trò, thiết lập cơ chế quản trị, rồi liên tục thu hẹp khoảng lệch giữa mục tiêu và thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c04e48d1-e66b-4205-8cb3-8d052bc95a5a','a1417300-6c24-4e67-a618-f39814b35dce',315,'text','Nói ngắn gọn, **ALIGN là tầng giúp tổ chức neo lại mục tiêu, nối đúng nguồn lực, tích hợp bộ máy, quản trị nhịp vận hành và liên tục thu hẹp các độ lệch trong quá trình tăng trưởng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b3d7c84-1729-4efc-bba4-5513965012b1','03-roadmap-to-be-sky-test','19cf738c-284a-4df0-afbd-312ecf2e0611',3,'Vì sao cần ALIGN?','vi-sao-can-align',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15f89b2c-b4d5-47d8-a621-d66a60164fac','2b3d7c84-1729-4efc-bba4-5513965012b1',316,'text','Một hệ thống chỉ trưởng thành thôi vẫn chưa đủ nếu các phần bên trong nó không đi cùng nhau. Tổ chức có thể rất rõ về định hướng, rất mạnh về nguyên tắc, rất tốt về quy trình, nhưng vẫn vận hành chệch nếu con người, dữ liệu, công cụ và nhịp quản trị chưa được liên kết thành một khối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdac49c7-bda3-45fd-8e2f-5b41085c68d5','2b3d7c84-1729-4efc-bba4-5513965012b1',317,'text','ALIGN tồn tại để làm cho sự đồng bộ trở thành năng lực có chủ đích, thay vì để hệ thống tự chờ mọi thứ “tự ăn khớp”. Nó giúp tổ chức giảm lệch pha giữa người, việc, nguồn lực và cơ chế phối hợp, từ đó tăng độ ổn định và tăng chất lượng thực thi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8','03-roadmap-to-be-sky-test','19cf738c-284a-4df0-afbd-312ecf2e0611',3,'Cấu trúc ALIGN','cau-truc-align',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bd07fd4-3423-49c8-ac09-90eaafb972f3','5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8',318,'text','- **Anchor** là neo mục tiêu chung, giữ cho toàn bộ hệ thống không trôi khỏi định hướng cốt lõi. Khi một tổ chức thiếu Anchor, các quyết định dễ bị kéo lệch bởi cảm xúc ngắn hạn, áp lực thị trường hoặc ưu tiên cục bộ của từng bộ phận.- Anchor là điểm tựa để mọi người cùng nhìn về một hướng. Nó không chỉ giữ mục tiêu trong đầu lãnh đạo, mà giữ mục tiêu ở trong nhịp vận hành của cả hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('513c6fa7-1f87-4ee9-9d4a-ef69f9de518b','5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8',319,'text','- **Link** là kết nối con người, dữ liệu, công cụ và nguồn lực để tránh vận hành rời rạc. Một hệ thống có quá nhiều mảnh ghép nhưng thiếu Link sẽ luôn phải tiêu hao năng lượng cho việc ghép nối lại từ đầu.- Link biến sự tồn tại song song thành sự phối hợp có ý nghĩa. Đây là lớp liên kết giúp tổ chức không bị phân mảnh thành những ốc đảo riêng lẻ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3db0dce-0a9f-48ab-8e42-66016adb587b','5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8',320,'text','- **Integrate** là tích hợp quy trình, vai trò và nhịp vận hành thành một hệ thống liền mạch. Nếu Link là nối các phần lại với nhau, thì Integrate là làm cho các phần ấy thật sự hoạt động như một cấu trúc thống nhất.- Integrate giúp hệ thống bớt đứt gãy giữa kế hoạch và thực thi, giữa chức năng và trách nhiệm, giữa công cụ và hành vi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fa9d72a-0515-473a-8906-970ea7650462','5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8',321,'text','- **Govern** là thiết lập cơ chế quản trị, phân quyền, trách nhiệm và nhịp họp để hệ thống đi đúng hướng. Không có Govern, hệ thống rất dễ rơi vào tình trạng ai cũng làm, nhưng không ai thật sự chịu trách nhiệm đến cùng.- Govern là phần giữ cho sự đồng bộ không chỉ đẹp trên sơ đồ, mà còn thật trong đời sống vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b93ecd4-8f1a-48bd-a1aa-ef11758ede94','5c4ff0e0-35d8-4fa0-9361-5f9a0772aff8',322,'text','- **Narrow** là thu hẹp khoảng lệch giữa mục tiêu và thực tế, giữa kế hoạch và thực thi, giữa các bộ phận trong hệ thống. Đây là đích đến của toàn bộ quá trình ALIGN: không phải tạo ra một hệ thống hoàn hảo ngay lập tức, mà liên tục giảm khoảng cách cho đến khi hệ thống chạy càng ngày càng khớp.- Narrow biến cải tiến thành một quá trình có hướng. Tổ chức càng mature thì càng phải giỏi trong việc thu hẹp độ lệch này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('46e702be-97ef-4ce9-a6ef-fabb5b8ebb62','03-roadmap-to-be-sky-test','19cf738c-284a-4df0-afbd-312ecf2e0611',3,'Ý nghĩa trong mạch phát triển','y-nghia-trong-mach-phat-trien',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b764e1f7-00dc-41a4-a79d-553acacb177d','46e702be-97ef-4ce9-a6ef-fabb5b8ebb62',323,'text','Trong mạch phát triển hiện tại, ALIGN đứng sau giai đoạn làm cho hệ thống trưởng thành hơn, vì chỉ khi hệ đã đủ rõ cấu trúc và ổn định thì việc đồng bộ hóa mới có hiệu lực thực sự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d560c7eb-804d-4fdf-b38a-6dcc14b98862','46e702be-97ef-4ce9-a6ef-fabb5b8ebb62',324,'text','Ở tầng này, tổ chức không còn chỉ hỏi “chúng ta có làm không?”, mà bắt đầu hỏi “chúng ta có làm cùng nhau, làm đúng nhịp và làm giảm lệch hay không?”. Đó là dấu hiệu của một hệ thống đã đi qua giai đoạn rời rạc và đang bước vào giai đoạn phối hợp có chủ đích.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b807040f-d888-42e8-af2b-bc44638d86dc','03-roadmap-to-be-sky-test','19cf738c-284a-4df0-afbd-312ecf2e0611',3,'Kết luận','ket-luan',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34d39f48-9131-408e-8afd-67303f199622','b807040f-d888-42e8-af2b-bc44638d86dc',325,'text','ALIGN là tầng giúp hệ thống thôi vận hành theo nhiều nhịp rời rạc và bắt đầu đi cùng một hướng. Khi mục tiêu đã được neo, nguồn lực đã được nối, bộ máy đã được tích hợp và cơ chế quản trị đã rõ, tổ chức mới có thể liên tục thu hẹp khoảng lệch giữa điều muốn làm và điều đang diễn ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7a875b3-bdec-490e-9d8f-931f0e4e3eb0','b807040f-d888-42e8-af2b-bc44638d86dc',326,'text','Nói cách khác, ALIGN biến “đồng bộ” từ một mong muốn thành một năng lực vận hành thật. Đó là cách một tổ chức trưởng thành không chỉ chạy nhanh hơn, mà còn chạy **khớp** hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38ed5cc7-ba0c-42ed-a2ae-4708e522f602','b807040f-d888-42e8-af2b-bc44638d86dc',327,'text','**Neo mục tiêu → Nối nguồn lực → Tích hợp hệ thống → Quản trị nhịp vận hành → Thu hẹp khoảng lệch.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b448afe5-a26c-47f4-adb5-ef2a1aa6425b','b807040f-d888-42e8-af2b-bc44638d86dc',328,'text','**Anchor the goal, Link the resources, Integrate the system, Govern the flow, Narrow the gap.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0dc09e16-f6c3-4994-be5f-9493d934bc6b','b807040f-d888-42e8-af2b-bc44638d86dc',329,'text','**Anchor → Link → Integrate → Govern → Narrow**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06e68b6b-1891-47e6-829c-7f7a58fc9143','03-roadmap-to-be-sky-test',NULL,2,'3.8 LAYER 8: P - PROSPER','38-layer-8-p-prosper',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61b10840-af8e-45cd-8dd9-5233a907ee5d','06e68b6b-1891-47e6-829c-7f7a58fc9143',330,'text','Nếu những tầng trước giúp hệ thống nhìn đúng, chuẩn hóa đúng, trưởng thành hơn và đi cùng một hướng, thì **PROSPER** là tầng giúp toàn bộ nỗ lực ấy biến thành **đà tăng trưởng kép**. Đây là giai đoạn hệ thống không chỉ tăng trưởng một lần, mà tự tạo ra nhiều vòng tăng trưởng mới bằng cách sinh sôi giá trị, tái đầu tư thành quả và làm cho mỗi chu kỳ sau mạnh hơn chu kỳ trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44a9ada6-9fcb-40c7-8957-ae5fb91d8124','06e68b6b-1891-47e6-829c-7f7a58fc9143',331,'text','Trong thực tế, một tổ chức có thể tăng trưởng mà không Prosper. Tăng trưởng đơn thuần chỉ nói rằng hệ thống có lớn lên; còn Prosper nói rằng hệ thống lớn lên theo cách có khả năng tạo thêm lực kéo cho chính mình. Đó là khác biệt giữa việc “đi lên một lần” và việc tạo ra một bánh đà tăng trưởng có thể tự quay.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('457043b9-475c-4d7f-98c6-79347622f10c','03-roadmap-to-be-sky-test','06e68b6b-1891-47e6-829c-7f7a58fc9143',3,'PROSPER là gì?','prosper-la-gi',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2472ee8f-7502-44e2-b17d-f1d872570e42','457043b9-475c-4d7f-98c6-79347622f10c',332,'text','**PROSPER** là framework mô tả quá trình sinh sôi, thịnh vượng và tạo hiệu ứng bánh đà tăng trưởng kép cho hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10f84068-f332-4553-8fe5-5bd0165092ac','457043b9-475c-4d7f-98c6-79347622f10c',333,'text','Nói ngắn gọn, **PROSPER là quá trình sinh sôi, tái đầu tư, tối ưu, mở rộng, lan truyền, làm giàu và đổi mới để tạo ra hiệu ứng bánh đà tăng trưởng kép.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ce48b698-402b-4944-8b0b-744d1784d7d4','03-roadmap-to-be-sky-test','06e68b6b-1891-47e6-829c-7f7a58fc9143',3,'Vì sao cần PROSPER?','vi-sao-can-prosper',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('145c9d7d-99dd-4f5b-9918-6b81e8c38dfe','ce48b698-402b-4944-8b0b-744d1784d7d4',334,'text','Một hệ thống muốn đi đường dài không thể chỉ chăm chăm tạo ra kết quả ngắn hạn. Nếu không có cơ chế tái đầu tư và tái sinh, mọi thành quả tốt cuối cùng cũng sẽ bị tiêu hao dần theo thời gian. PROSPER tồn tại để biến kết quả thành nhiên liệu cho vòng tăng trưởng kế tiếp, thay vì để thành quả bị tiêu thụ hết trong hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b63b3818-ff21-4c0a-aa78-cce151439424','ce48b698-402b-4944-8b0b-744d1784d7d4',335,'text','Điều này rất quan trọng với tổ chức nha khoa, vì tăng trưởng bền không chỉ đến từ thu hút khách mới, mà còn đến từ khả năng tạo niềm tin, kích hoạt giới thiệu, làm giàu hệ sinh thái và làm mới liên tục cách tổ chức tạo ra giá trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bf01303c-9a33-465b-937b-2d5017345df3','03-roadmap-to-be-sky-test','06e68b6b-1891-47e6-829c-7f7a58fc9143',3,'Cấu trúc PROSPER','cau-truc-prosper',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0353927d-cd14-45c6-8cee-7d926a77ca2a','bf01303c-9a33-465b-937b-2d5017345df3',336,'text','- **Proliferate** là sinh sôi và lan rộng giá trị theo cấp số nhân để tạo thêm lực cho mỗi vòng tăng trưởng. - Tổ chức không chỉ tạo ra kết quả, mà còn làm cho kết quả đó sinh ra thêm tác động mới, người dùng mới, niềm tin mới và cơ hội mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd1c2bce-2281-4781-94aa-3c682e680ac7','bf01303c-9a33-465b-937b-2d5017345df3',337,'text','- **Reinvest** là tái đầu tư kết quả tốt trở lại vào con người, quy trình, nội dung và hạ tầng. - Nếu không tái đầu tư, tăng trưởng sẽ chỉ là đỉnh ngắn hạn. Reinvest giúp thành quả được chuyển hóa thành nền tảng mới cho chu kỳ tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7389da4b-5758-46ea-a37e-123ae0ab24d1','bf01303c-9a33-465b-937b-2d5017345df3',338,'text','- **Optimize** là tối ưu liên tục để giảm ma sát và tăng hiệu suất của toàn hệ thống. - Đây là bước làm cho tổ chức ngày càng nhẹ hơn ở những chỗ nặng, nhanh hơn ở những chỗ chậm, và rõ hơn ở những chỗ còn mù.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ed9536f-8f0a-41d1-a603-1e14be348e86','bf01303c-9a33-465b-937b-2d5017345df3',339,'text','- **Scale** là mở rộng có kiểm soát khi hệ đã đủ chắc, đủ rõ và đủ bền. - Scale không phải mở rộng bằng mọi giá; nó là mở rộng đúng lúc, đúng nền và đúng năng lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65e0477e-6ea8-4a08-9535-fd2479145e85','bf01303c-9a33-465b-937b-2d5017345df3',340,'text','- **Propagate** là lan truyền giá trị qua referral, cộng đồng và các lớp tài sản niềm tin. - Đây là lúc giá trị không còn nằm riêng trong phòng khám, mà bắt đầu đi xa hơn qua sự giới thiệu, chia sẻ và cộng hưởng của những người đã tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ee3807f-aaa2-457f-ac03-b9c4abf0bf08','bf01303c-9a33-465b-937b-2d5017345df3',341,'text','- **Enrich** là làm giàu hệ sinh thái bằng dữ liệu, kinh nghiệm và nguồn lực mới. - Khi hệ thống giàu hơn, nó không chỉ có thêm tài sản, mà còn có thêm chiều sâu để tiếp tục phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb1ba422-5aee-48ed-bfc1-45647dcddd3e','bf01303c-9a33-465b-937b-2d5017345df3',342,'text','- **Renew** là làm mới vòng tăng trưởng để hệ luôn sống động và không bị cũ hóa. - Renew giúp tổ chức không bị mắc kẹt trong một mô hình đã thành công quá lâu đến mức trở nên già nua.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('213ce1f1-d14d-41b0-b6cf-7326a129c43d','03-roadmap-to-be-sky-test','06e68b6b-1891-47e6-829c-7f7a58fc9143',3,'Ý nghĩa trong mạch phát triển','y-nghia-trong-mach-phat-trien',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5ca53ff-01f5-44fe-aafe-1fc2ad569736','213ce1f1-d14d-41b0-b6cf-7326a129c43d',343,'text','Trong mạch phát triển hiện tại, PROSPER là tầng giúp hệ thống không chỉ tăng trưởng một lần mà tự tạo ra nhiều vòng tăng trưởng mới, nhờ đó giá trị, niềm tin, referral và năng lực nội bộ cùng nhân lên theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ebfbd95-6d39-45d9-9829-017d78b9b744','213ce1f1-d14d-41b0-b6cf-7326a129c43d',344,'text','Ở đây, tăng trưởng không còn là một đường thẳng đi lên rồi dừng lại. Nó trở thành một chu trình sống động, nơi mỗi vòng tăng trưởng tốt sẽ tạo nền cho vòng tiếp theo mạnh hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e1395fba-541e-444c-a165-55eb118ebd3c','03-roadmap-to-be-sky-test','06e68b6b-1891-47e6-829c-7f7a58fc9143',3,'Kết luận:','ket-luan',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34dd6238-d547-4822-bbb5-cec5e83c9a74','e1395fba-541e-444c-a165-55eb118ebd3c',345,'text','PROSPER là tầng giúp hệ thống tăng trưởng theo kiểu tự sinh sôi, tự tái đầu tư và tự làm mới chính mình. Khi một tổ chức biết biến kết quả thành nhiên liệu cho chu kỳ tiếp theo, nó không chỉ lớn lên một lần mà có thể tạo ra nhiều vòng tăng trưởng mới theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d23133d3-7181-4510-b459-78cc8d3240ff','e1395fba-541e-444c-a165-55eb118ebd3c',346,'text','Nói cách khác, PROSPER không chỉ làm cho hệ thống **tăng trưởng**, mà làm cho hệ thống **thịnh vượng có đà**. Đó là sự tăng trưởng biết sinh ra tăng trưởng, biết nuôi lại chính mình và biết mở rộng bằng niềm tin, dữ liệu và giá trị thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3d3bcb8-a2e5-4835-8154-7a0db95f0b45','e1395fba-541e-444c-a165-55eb118ebd3c',347,'text','**Sinh sôi → Tái đầu tư → Tối ưu → Mở rộng → Lan truyền → Làm giàu → Đổi mới.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a023b7c6-ad38-42ee-a5a9-5a64a3ad647b','e1395fba-541e-444c-a165-55eb118ebd3c',348,'text','**Proliferate → Reinvest → Optimize → Scale → Propagate → Enrich → Renew.**',NULL,NULL,NULL,NULL,NULL);
